import React, { useEffect, useState, useContext } from 'react';
import { View, Text } from 'react-native';
import { MaterialCommunityIcons } from '@expo/vector-icons';

import { AppContext } from '../../../shared/services/AppCore';
import style, { tokens } from '../../../shared/theme/Theme';
import Translator from '../../../shared/i18n/Translator';
import BdeService, { BdeAnnonce } from '../services/BdeService';
import { withHeaderAnimation } from '../../../shared/navigation/NavHelpers';

import { CampusListLayout } from '../components/CampusListLayout';
import { CampusCard } from '../components/CampusCard';

export interface BdeScreenProps {
    navigation: { navigate: (screen: string, params?: Record<string, unknown>) => void; setOptions?: any };
    onAnimatedScroll?: (event: unknown) => void;
}

function BdeScreen({ navigation, onAnimatedScroll }: BdeScreenProps) {
    const { themeName } = useContext(AppContext);
    const theme = style.Theme[themeName];

    const [annonces, setAnnonces] = useState<BdeAnnonce[]>([]);
    const [loading, setLoading] = useState<boolean>(true);

    useEffect(() => {
        let mounted = true;
        const loadData = async () => {
            setLoading(true);
            const data = await BdeService.fetchAnnonces();
            if (!mounted) return;
            setAnnonces(data);
            setLoading(false);
        };

        loadData();
        return () => { mounted = false; };
    }, []);

    const renderItem = ({ item }: { item: BdeAnnonce }) => (
        <CampusCard
            title={item.title}
            imageUrl={item.image_url}
            onPress={() => navigation.navigate('BdeDetail', { annonce: item })}
        >
            <View style={{ flexDirection: 'row', alignItems: 'center', marginBottom: item.info_label ? 4 : 0 }}>
                <MaterialCommunityIcons name="account" size={16} color={theme.fontSecondary} />
                <Text style={{ fontSize: tokens.fontSize.sm, color: theme.fontSecondary, marginLeft: 4, flex: 1 }} numberOfLines={1}>
                    {item.issuer_name}
                </Text>
            </View>

            {item.info_label ? (
                <View style={{ flexDirection: 'row', alignItems: 'flex-start' }}>
                    <MaterialCommunityIcons name="information-outline" size={16} color={theme.fontSecondary} style={{ marginTop: 2 }} />
                    <Text style={{ fontSize: tokens.fontSize.sm, color: theme.fontSecondary, marginLeft: 4, flex: 1, lineHeight: 20 }} numberOfLines={2}>
                        {item.info_label}
                    </Text>
                </View>
            ) : null}
        </CampusCard>
    );

    return (
        <CampusListLayout
            data={annonces}
            loading={loading}
            renderItem={renderItem}
            onAnimatedScroll={onAnimatedScroll}
            navigation={navigation}

            emptyIcon="party-popper"
            emptyMessage={Translator.get('NO_RESULTS' as Parameters<typeof Translator.get>[0]) || 'Aucune annonce'}
        />
    );
}

export default withHeaderAnimation(BdeScreen);

import React, { useEffect, useState, useContext, useRef } from 'react';
import { View, Text, ScrollView, ActivityIndicator, TouchableOpacity, FlatList } from 'react-native';
import { SafeAreaView, useSafeAreaInsets } from 'react-native-safe-area-context';
import { MaterialCommunityIcons } from '@expo/vector-icons';

import { CrousService, CrousDayMenu } from '../services/CrousService';
import style, { tokens } from '../../../shared/theme/Theme';
import { AppContext } from '../../../shared/services/AppCore';
import Translator from '../../../shared/i18n/Translator';

export default function CrousMenuScreen({ route, navigation }: { route: any; navigation: import('@react-navigation/native').NavigationProp<Record<string, unknown>> & { setOptions: (options: unknown) => void } }) {
    const { restaurantId, restaurantName } = route.params;
    const AppContextValues = useContext(AppContext) as { themeName: 'light' | 'dark' };
    const theme = style.Theme[AppContextValues.themeName];
    const insets = useSafeAreaInsets();

    const [menus, setMenus] = useState<CrousDayMenu[]>([]);
    const [loading, setLoading] = useState(true);
    const [selectedIndex, setSelectedIndex] = useState(0);
    const flatListRef = useRef<FlatList>(null);
    const mountedRef = useRef(true);
    const scrollTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    useEffect(() => {
        return () => {
            mountedRef.current = false;
            if (scrollTimeoutRef.current) clearTimeout(scrollTimeoutRef.current);
        };
    }, []);

    useEffect(() => {
        navigation.setOptions({
            headerTitle: () => (
                <Text style={{ color: theme.primary, fontSize: tokens.fontSize.xl, fontWeight: tokens.fontWeight.bold as never }}>
                    {Translator.get('MENU')}
                </Text>
            ),
            headerTitleAlign: 'center'
        });
        loadMenu();
    }, [navigation, theme]);

    useEffect(() => {
        loadMenu();
    }, []);

    useEffect(() => {
        if (menus.length > 0 && flatListRef.current) {
            const timerId = setTimeout(() => {
                flatListRef.current?.scrollToIndex({
                    index: selectedIndex,
                    animated: true,
                    viewPosition: 0.5
                });
            }, 100);
            return () => clearTimeout(timerId);
        }
    }, [selectedIndex, menus])

    const loadMenu = async () => {
        setLoading(true);
        const data = await CrousService.fetchRestaurantMenu(restaurantId);
        if (!mountedRef.current) return;
        setMenus(data);
        setLoading(false);
    };

    // "2024-03-25" -> "Lun 25"
    const formatDate = (dateString: string | null) => {
        if (!dateString) return Translator.get('UNKNOWN');

        const d = new Date(dateString);
        if (isNaN(d.getTime())) return dateString;

        const dayKeys = ['DAY_SUN', 'DAY_MON', 'DAY_TUE', 'DAY_WED', 'DAY_THU', 'DAY_FRI', 'DAY_SAT'];
        const translatedDay = Translator.get(dayKeys[d.getDay()] as Parameters<typeof Translator.get>[0]);
        return `${translatedDay} ${d.getDate()}`;
    };

    if (loading) {
        return (
            <SafeAreaView edges={['left', 'right']} style={{ flex: 1, backgroundColor: theme.courseBackground }}>
                <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
                    <ActivityIndicator size="large" color={theme.accent ?? theme.primary} />
                </View>
            </SafeAreaView>
        );
    }

    if (menus.length === 0) {
        return (
            <SafeAreaView edges={['left', 'right']} style={{ flex: 1, backgroundColor: theme.courseBackground }}>
                <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center', padding: tokens.space.xl }}>
                    <MaterialCommunityIcons name="food-off" size={48} color={theme.fontSecondary} style={{ marginBottom: tokens.space.md }} />
                    <Text style={{ color: theme.fontSecondary, fontSize: tokens.fontSize.md, textAlign: 'center' }}>
                        {Translator.get('NO_MENU_PUBLISHED')}
                    </Text>
                </View>
            </SafeAreaView>
        );
    }

    const currentMenu = menus[selectedIndex];

    const getDishIcon = (dishName: string) => {
        const str = dishName.toLowerCase();

        const has = (words: string) => {
            return new RegExp(`(^|[\\s'’\\-])(${words})(s|x)?([\\s'’.,;!?:\\-]|$)`, 'i').test(str);
        };

        if (has('fermé|ferme|fermée|non communiqué|modification|ou|structure|réserve|exceptionnel|formule|le menu')) return 'information-outline';

        if (has('bretonne|sans viande|sans porc|végé|veggie|vegan|steak végétal|tofu|soja|falafel')) return 'leaf';

        if (has('boisson|soda|coca|fanta|sprite|eau|jus|thé|the|café|cafe')) return 'bottle-soda';

        if (has('pizza|pasta box')) return 'pizza';
        if (has('frite|chips|snack')) return 'french-fries';
        if (has('burger|hamburger')) return 'hamburger';
        if (has('tacos|fajita')) return 'taco';
        if (has('sandwich|baguette|panini|wrap|croque|hot-dog')) return 'baguette';

        if (has('poulet|boeuf|bœuf|porc|veau|agneau|saucisse|viande|steak|lardon|chorizo|dinde|canard|merguez|filet|rôti|haché|kebab|jambon|bacon|cordon bleu|boulette|escalope|pâté|charcuterie')) return 'food-drumstick';
        if (has('poisson|saumon|cabillaud|colin|merlu|crevette|calamar|thon|truite|lieu|moule|fruit de mer|hoki|encornet|surimi')) return 'fish';
        if (has('oeuf|œuf|omelette')) return 'egg';

        if (has('entrée|soupe|potage|velouté|bouillon|gaspacho|crudité|hors d')) return 'bowl-mix';

        if (has('fromage|brie|camembert|chèvre|chevre|mozza|emmental|cantal|gruyère|parmesan|kiri|roquefort')) return 'cheese';

        if (has('viennoiserie|croissant|chocolatine|brioche')) return 'food-croissant';
        if (has('fruit|pomme|banane|orange|kiwi|ananas|poire|fraise|framboise|pêche|abricot|raisin|mangue|melon|pastèque|citron|clémentine|compote') && !has('pomme de terre')) return 'food-apple';
        if (has('yaourt|lacté|petit suisse|fromage blanc|skyr|faisselle|glace|crème')) return 'silverware-spoon';
        if (has('dessert|tarte|pâtisserie|gâteau|cookie|muffin|brownie|entremet|flan|caramel|vanille|chocolat|bonbon|barre|confiserie|macaron|gaufre|crêpe')) return 'cupcake';

        if (has('salade|légume|haricot|lentille|pois|carotte|brocoli|chou|courgette|aubergine|épinard|poireau|champignon|céleri|ratatouille|tomate|concombre|maïs')) return 'leaf';

        if (has('coquillette|riz|pâte|spaghetti|macaroni|penne|ravioli|semoule|boulgour|blé|quinoa|pomme de terre|purée|gnocchi|nouille')) return 'pasta';

        return 'circle-medium';
    };

    const renderMeal = (mealTitle: string, categories: { name: string, dishes: string[] }[], mealType: 'midi' | 'soir') => {
        if (!categories || categories.length === 0) return null;

        // Le soleil pour le midi, la lune pour le soir
        const iconHeader = mealType === 'midi' ? 'white-balance-sunny' : 'moon-waning-crescent';

        return (
            <View style={{ marginBottom: tokens.space.xl }}>
                {/* Titre du repas */}
                <View style={{ flexDirection: 'row', alignItems: 'center', marginTop: tokens.space.sm, marginBottom: tokens.space.md, paddingHorizontal: tokens.space.md }}>
                    <MaterialCommunityIcons 
                        name={iconHeader} 
                        size={20} 
                        color={theme.accent ?? theme.primary} 
                    />
                    <Text style={{ fontSize: tokens.fontSize.lg, fontWeight: tokens.fontWeight.bold as never, color: theme.font, marginLeft: tokens.space.sm }}>
                        {mealTitle}
                    </Text>
                </View>

                {/* Liste des catégories */}
                {categories.map((cat, index) => (
                    <View key={index} style={[style.course.card as never, { 
                        backgroundColor: theme.cardBackground, 
                        borderColor: theme.border, 
                        borderWidth: 1 
                    }]}>
                        <Text style={{ fontSize: tokens.fontSize.md, fontWeight: tokens.fontWeight.semibold as never, color: theme.accent ?? theme.primary, marginBottom: tokens.space.sm }}>
                            {cat.name}
                        </Text>

                        {cat.dishes.length > 0 ? cat.dishes.map((dish: string, dIdx: number) => (
                            <View key={dIdx} style={{ flexDirection: 'row', alignItems: 'flex-start', marginBottom: 6 }}>
                                {/* Utilisation de l'icône intelligente au lieu du point classique */}
                                <MaterialCommunityIcons 
                                    name={getDishIcon(dish)} 
                                    size={16} 
                                    color={getDishIcon(dish) === 'leaf' ? '#4caf50' : theme.fontSecondary} 
                                    style={{ marginRight: 6, marginTop: 2 }} 
                                />
                                <Text style={{ fontSize: tokens.fontSize.sm, color: theme.font, flex: 1, lineHeight: 20 }}>{dish}</Text>
                            </View>
                        )) : (
                            <Text style={{ fontSize: tokens.fontSize.sm, color: theme.fontSecondary, fontStyle: 'italic' }}>{Translator.get('NOT_SPECIFIED')}</Text>
                        )}
                    </View>
                ))}
            </View>
        );
    };

    return (
        <SafeAreaView edges={['left', 'right']} style={{ flex: 1, backgroundColor: theme.courseBackground }}>

            {/* ── Bandeau des dates défilant horizontalement ── */}
            <View style={{ backgroundColor: theme.cardBackground, borderBottomWidth: 1, borderBottomColor: theme.border, paddingVertical: tokens.space.sm, paddingTop: (insets.top || 0) + 65 }}>

                <Text 
                    style={{
                        fontSize: tokens.fontSize.xl,
                        fontWeight: tokens.fontWeight.bold as never,
                        color: theme.fontSecondary,
                        textAlign: 'left',
                        paddingHorizontal: tokens.space.md,
                        marginBottom: tokens.space.md,
                    }} 
                    numberOfLines={1}
                >
                    {restaurantName || Translator.get('RESTAURANT_U')}
                </Text>

                <FlatList
                    ref={flatListRef}
                    horizontal
                    showsHorizontalScrollIndicator={false}
                    data={menus}
                    keyExtractor={(item) => item.date}
                    contentContainerStyle={{ paddingHorizontal: tokens.space.sm }}
                    onScrollToIndexFailed={(info) => {
                        scrollTimeoutRef.current = setTimeout(() => {
                            flatListRef.current?.scrollToIndex({ index: info.index, animated: true, viewPosition: 0.5 });
                        }, 500);
                    }}
                    renderItem={({ item, index }) => {
                        const isSelected = index === selectedIndex;
                        const primaryColor = theme.accent ?? theme.primary;

                        return (
                            <TouchableOpacity 
                                onPress={() => setSelectedIndex(index)}
                                style={{
                                    paddingHorizontal: tokens.space.md,
                                    paddingVertical: tokens.space.sm,
                                    marginHorizontal: tokens.space.xs,
                                    borderRadius: tokens.radius.md,
                                    backgroundColor: theme.greyBackground,
                                    // On fixe la bordure à 2 de manière permanente pour éviter que le texte saute
                                    borderWidth: 2,
                                    borderColor: isSelected ? primaryColor : 'transparent',
                                }}
                            >
                                <Text style={{ 
                                    color: isSelected ? primaryColor : theme.fontSecondary,
                                    fontWeight: isSelected ? (tokens.fontWeight.bold as never) : (tokens.fontWeight.medium as never),
                                    fontSize: tokens.fontSize.sm
                                }}>
                                    {formatDate(item.date)}
                                </Text>
                            </TouchableOpacity>
                        );
                    }}
                />
            </View>

            {/* ── Affichage des plats ── */}
            <ScrollView style={{ flex: 1, paddingTop: tokens.space.md }}>
                {currentMenu.midi?.length === 0 && currentMenu.soir?.length === 0 ? (
                    <Text style={{ textAlign: 'center', color: theme.fontSecondary, marginTop: tokens.space.xl }}>
                        {Translator.get('NO_DISH_INFO')}
                    </Text>
                ) : (
                    <>
                        {renderMeal(Translator.get('LUNCH'), currentMenu.midi, 'midi')}
                        {renderMeal(Translator.get('DINNER'), currentMenu.soir, 'soir')}
                    </>
                )}
                <View style={{ height: tokens.space.xxl }} />
            </ScrollView>

        </SafeAreaView>
    );
}

import React, { useState, useEffect, useContext, useMemo } from 'react';
import { View, Text } from 'react-native';
import { MaterialCommunityIcons, MaterialIcons } from '@expo/vector-icons';

import { AppContext } from '../../../shared/services/AppCore';
import style, { tokens } from '../../../shared/theme/Theme';
import Translator from '../../../shared/i18n/Translator';
import { CrousService, CrousRestaurant } from '../services/CrousService';
import { withHeaderAnimation } from '../../../shared/navigation/NavHelpers';

import { CampusListLayout } from '../components/CampusListLayout';
import { CampusCard } from '../components/CampusCard';
import { useFavorites } from '../hooks/useFavorites';
import { useCampusLocation } from '../hooks/useCampusLocation';
import { useSavedFilter } from '../hooks/useSavedFilter';

function CrousScreen({ navigation, onAnimatedScroll }: any) {
    const AppContextValues = useContext(AppContext) as { themeName: 'light' | 'dark' };
    const themeName = AppContextValues.themeName ?? 'light';
    const theme = style.Theme[themeName];

    const { fetchLocation } = useCampusLocation();
    const { favorites, toggleFavorite } = useFavorites('crous_favorites');
    const [selectedFilter, setSelectedFilter] = useSavedFilter('crous_filter', 'all');

    const [searchText, setSearchText] = useState('');
    const [restaurants, setRestaurants] = useState<CrousRestaurant[]>([]);
    const [loading, setLoading] = useState<boolean>(true);

    useEffect(() => {
        let mounted = true;
        const loadData = async () => {
            setLoading(true);
            const { lat, lon } = await fetchLocation();

            const data = await CrousService.fetchRestaurantsBordeaux(lat, lon);
            if (!mounted) return;
            setRestaurants(data);
            setLoading(false);
        };

        loadData();
        return () => { mounted = false; };
    }, [fetchLocation]);

    const filteredData = useMemo(() => {
        let result = [...restaurants].sort((a, b) => {
            const aFav = favorites.includes(a.id);
            const bFav = favorites.includes(b.id);
            if (aFav && !bFav) return -1;
            if (!aFav && bFav) return 1;
            return (a.distance || 0) - (b.distance || 0);
        });

        return result.filter(item => {
            if (selectedFilter !== 'all') {
                const isRestoU = item.title.includes("Crous Cafet") || item.title.includes("Resto U");
                const isMarket = item.title.includes("Crous Moovy Market") || item.title.includes("Crous Market");

                if (selectedFilter === 'resto' && !isRestoU) return false;
                if (selectedFilter === 'market' && !isMarket) return false;
            }

            if (searchText.trim().length > 0) {
                const query = searchText.toLowerCase().trim();
                const matchName = item.title.toLowerCase().includes(query);
                const matchCity = item.short_desc && item.short_desc.toLowerCase().includes(query);
                if (!matchName && !matchCity) return false;
            }

            return true;
        });
    }, [restaurants, favorites, searchText, selectedFilter]);

    const filterOptions = [
        { id: 'all', label: Translator.get('ALL_ESTABLISHMENTS' as Parameters<typeof Translator.get>[0]) },
        { id: 'resto', label: Translator.get('RESTO_U' as Parameters<typeof Translator.get>[0]) },
        { id: 'market', label: Translator.get('CROUS_MARKET' as Parameters<typeof Translator.get>[0]) }
    ];

    const renderItem = ({ item }: { item: CrousRestaurant }) => (
        <CampusCard
            title={item.title}
            imageUrl={item.image_url}
            isFavorite={favorites.includes(item.id)}
            onToggleFavorite={() => toggleFavorite(item.id)}
            onPress={() => navigation.navigate('CrousMenu', {
                restaurantId: item.id,
                restaurantName: item.title,
                location: { lat: item.lat, lon: item.lon }
            })}
        >
            <View style={{ flexDirection: 'row', alignItems: 'center', marginBottom: tokens.space.xs }}>
                <MaterialIcons name="location-on" size={16} color={theme.fontSecondary} />
                <Text style={{ fontSize: tokens.fontSize.sm, color: theme.fontSecondary, marginLeft: 4, flex: 1 }}>
                    {item.short_desc}
                </Text>

                {item.distance !== undefined && (
                    <View style={{
                        flexDirection: 'row',
                        alignItems: 'center',
                        backgroundColor: `${theme.primary}15`,
                        paddingHorizontal: tokens.space.sm,
                        paddingVertical: 4,
                        borderRadius: tokens.radius.md,
                    }}>
                        <MaterialCommunityIcons name="walk" size={14} color={theme.primary} />
                        <Text style={{
                            fontSize: tokens.fontSize.sm,
                            fontWeight: tokens.fontWeight.bold as never,
                            color: theme.primary,
                            marginLeft: 4
                        }}>
                            {item.distance < 1
                                ? `${Math.round(item.distance * 1000)} m`
                                : `${item.distance.toFixed(1)} km`}
                        </Text>
                    </View>
                )}
            </View>

            <View style={{ flexDirection: 'row', alignItems: 'flex-start' }}>
                <MaterialCommunityIcons name="calendar-clock" size={16} color={theme.fontSecondary} style={{ marginTop: 2 }} />
                <Text
                    style={{
                        fontSize: tokens.fontSize.sm,
                        color: theme.fontSecondary,
                        marginLeft: 6,
                        flex: 1,
                        lineHeight: 20
                    }}
                    numberOfLines={2}
                >
                    {item.opening}
                </Text>
            </View>
        </CampusCard>
    );

    return (
        <CampusListLayout
            data={filteredData}
            loading={loading}
            renderItem={renderItem}
            onAnimatedScroll={onAnimatedScroll}
            navigation={navigation}

            hasSearch={true}
            searchText={searchText}
            onSearchChange={setSearchText}
            searchPlaceholder={Translator.get('SEARCH_RESTO_CITY' as Parameters<typeof Translator.get>[0])}

            filterOptions={filterOptions}
            selectedFilter={selectedFilter}
            onFilterChange={setSelectedFilter}

            emptyIcon="store-off-outline"
            emptyMessage={Translator.get('NO_RU_NEARBY')}
        />
    );
}

export default withHeaderAnimation(CrousScreen);

import React, { useContext, useRef, useState, useEffect } from 'react';
import { View, Text, StyleSheet, Animated } from 'react-native';
import { SafeAreaInsetsContext } from 'react-native-safe-area-context';

import style, { tokens } from '../../../shared/theme/Theme';
import { AppContext } from '../../../shared/services/AppCore';
import Translator from '../../../shared/i18n/Translator';
import { useCampusLocation } from '../hooks/useCampusLocation';

import { BdeSection } from './components/BdeSection';
import { CrousSection } from './components/CrousSection';
import { LibrarySection } from './components/LibrarySection';
import { FreeRoomSection } from './components/FreeRoomSection';

const CampusDashboard = ({ navigation }: { navigation: any }) => {
    const { themeName } = useContext(AppContext);
    const theme = style.Theme[themeName];

    // Fetch location once for the whole dashboard to avoid multiple requests
    const { fetchLocation } = useCampusLocation();
    const [location, setLocation] = useState<{ lat?: number, lon?: number }>({});

    useEffect(() => {
        let mounted = true;
        fetchLocation().then(({ lat, lon }) => {
            if (mounted) setLocation({ lat, lon });
        });
        return () => { mounted = false; };
    }, [fetchLocation]);

    const scrollY = useRef(new Animated.Value(0)).current;

    const renderHeader = (insets: any) => {
        const topPadding = (insets?.top || 0);

        const opacity = scrollY.interpolate({
            inputRange: [0, 50],
            outputRange: [1, 0],
            extrapolate: 'clamp'
        });

        return (
            <Animated.View style={[styles.headerContainer, { paddingTop: topPadding, backgroundColor: 'transparent', opacity }]}>
                <View style={[styles.headerContent, { paddingHorizontal: tokens.space.md }]}>
                    <Text style={[styles.greetingText, { color: theme.font }]}>
                        {Translator.get('CAMPUS') || 'Campus'}
                    </Text>
                </View>
            </Animated.View>
        );
    };

    return (
        <SafeAreaInsetsContext.Consumer>
            {(insets) => (
                <View style={[styles.container, { backgroundColor: theme.background }]}>
                    {renderHeader(insets)}

                    <Animated.ScrollView
                        onScroll={Animated.event(
                            [{ nativeEvent: { contentOffset: { y: scrollY } } }],
                            { useNativeDriver: true }
                        )}
                        scrollEventThrottle={16}
                        showsVerticalScrollIndicator={false}
                        contentContainerStyle={{ paddingTop: (insets?.top || 0) + 60, paddingBottom: tokens.space.xxl + 80 }}
                    >
                        <BdeSection navigation={navigation} />
                        <CrousSection navigation={navigation} userLat={location.lat} userLon={location.lon} />
                        <LibrarySection navigation={navigation} userLat={location.lat} userLon={location.lon} />
                        <FreeRoomSection navigation={navigation} userLat={location.lat} userLon={location.lon} />
                    </Animated.ScrollView>
                </View>
            )}
        </SafeAreaInsetsContext.Consumer>
    );
};

const styles = StyleSheet.create({
    container: {
        flex: 1,
    },
    headerContainer: {
        position: 'absolute',
        top: 0,
        left: 0,
        right: 0,
        zIndex: 10,
        paddingBottom: tokens.space.sm,
    },
    headerContent: {
        flexDirection: 'row',
        alignItems: 'center',
    },
    greetingText: {
        fontSize: 34,
        fontWeight: tokens.fontWeight.bold as any,
        fontFamily: 'Montserrat_600SemiBold',
        marginBottom: tokens.space.md,
    },
});

export default CampusDashboard;

import React, { useEffect, useState, useContext, useRef } from 'react';
import { View, Text, FlatList, TouchableOpacity, Image, ActivityIndicator, Dimensions } from 'react-native';
import { MaterialCommunityIcons, MaterialIcons } from '@expo/vector-icons';
import Reanimated, { FadeIn, LinearTransition } from 'react-native-reanimated';

import style, { tokens } from '../../../../shared/theme/Theme';
import { AppContext } from '../../../../shared/services/AppCore';
import Translator from '../../../../shared/i18n/Translator';
import BdeService, { BdeAnnonce } from '../../services/BdeService';

const { width } = Dimensions.get('window');
const CARD_WIDTH = width * 0.85;

export function BdeSection({ navigation }: { navigation: any }) {
    const { themeName } = useContext(AppContext);
    const theme = style.Theme[themeName];

    const [annonces, setAnnonces] = useState<BdeAnnonce[]>([]);
    const [loading, setLoading] = useState(true);
    const mountedRef = useRef(true);

    useEffect(() => {
        mountedRef.current = true;
        BdeService.fetchAnnonces().then(data => {
            if (mountedRef.current) {
                setAnnonces(data);
                setLoading(false);
            }
        }).catch(() => {
            if (mountedRef.current) setLoading(false);
        });
        return () => { mountedRef.current = false; };
    }, []);

    const renderCard = ({ item }: { item: BdeAnnonce }) => (
        <Reanimated.View
            entering={FadeIn}
            layout={LinearTransition.springify()}
        >
            <TouchableOpacity
                activeOpacity={0.9}
                onPress={() => navigation.navigate('BdeDetail', { annonce: item })}
                style={{
                    width: CARD_WIDTH,
                    backgroundColor: theme.cardBackground,
                    borderRadius: tokens.radius.xl,
                    marginRight: tokens.space.md,
                    ...tokens.shadow.md,
                    overflow: 'hidden',
                }}
            >
                <View style={{ width: '100%', height: 160, backgroundColor: theme.greyBackground }}>
                    {item.image_url ? (
                        <Image source={{ uri: item.image_url }} style={{ position: 'absolute', width: '100%', height: '100%', resizeMode: 'cover' }} />
                    ) : null}
                </View>

                <View style={{ padding: tokens.space.md }}>
                    <Text style={{ fontSize: tokens.fontSize.lg, fontWeight: tokens.fontWeight.bold as any, color: theme.font, flexShrink: 1, marginBottom: 4 }} numberOfLines={1}>
                        {item.title}
                    </Text>

                    <View style={{ flexDirection: 'row', alignItems: 'center', marginBottom: item.info_label ? 4 : 0 }}>
                        <MaterialCommunityIcons name="account" size={16} color={theme.fontSecondary} />
                        <Text style={{ fontSize: tokens.fontSize.sm, color: theme.fontSecondary, marginLeft: 4, flex: 1 }} numberOfLines={1}>
                            {item.issuer_name}
                        </Text>
                    </View>

                    {item.info_label ? (
                        <View style={{ flexDirection: 'row', alignItems: 'flex-start' }}>
                            <MaterialCommunityIcons name="information-outline" size={16} color={theme.fontSecondary} style={{ marginTop: 2 }} />
                            <Text style={{ fontSize: tokens.fontSize.sm, color: theme.fontSecondary, marginLeft: 4, flex: 1, lineHeight: 20 }} numberOfLines={2}>
                                {item.info_label}
                            </Text>
                        </View>
                    ) : null}
                </View>
            </TouchableOpacity>
        </Reanimated.View>
    );

    if (!loading && annonces.length === 0) return null;

    return (
        <View style={{ marginTop: tokens.space.md }}>
            <TouchableOpacity 
                style={{ flexDirection: 'row', alignItems: 'center', paddingHorizontal: tokens.space.md, marginBottom: tokens.space.sm }}
                onPress={() => navigation.navigate('Bde')}
                activeOpacity={0.7}
            >
                <Text style={{ fontSize: 22, fontWeight: tokens.fontWeight.bold as any, fontFamily: 'Montserrat_600SemiBold', color: theme.font }}>
                    {Translator.get('STUDENT_LIFE') || 'Student life'}
                </Text>
                <MaterialIcons name="chevron-right" size={26} color={theme.fontSecondary} style={{ marginLeft: 2 }} />
            </TouchableOpacity>

            {loading ? (
                <ActivityIndicator style={{ margin: tokens.space.xl }} color={theme.primary} />
            ) : (
                <FlatList
                    horizontal
                    data={annonces}
                    renderItem={renderCard}
                    keyExtractor={item => item.id}
                    showsHorizontalScrollIndicator={false}
                    snapToInterval={CARD_WIDTH + tokens.space.md}
                    decelerationRate="fast"
                    contentContainerStyle={{ paddingHorizontal: tokens.space.md, paddingBottom: tokens.space.lg }}
                />
            )}
        </View>
    );
}

import React, { useEffect, useState, useContext, useRef, useMemo } from 'react';
import { View, Text, FlatList, TouchableOpacity, Image, ActivityIndicator, Dimensions } from 'react-native';
import { MaterialCommunityIcons, MaterialIcons } from '@expo/vector-icons';
import Reanimated, { FadeIn, LinearTransition } from 'react-native-reanimated';

import style, { tokens } from '../../../../shared/theme/Theme';
import { AppContext } from '../../../../shared/services/AppCore';
import Translator from '../../../../shared/i18n/Translator';
import { CrousService, CrousRestaurant } from '../../services/CrousService';
import { useFavorites } from '../../hooks/useFavorites';
import { useSavedFilter } from '../../hooks/useSavedFilter';

const defaultRuImage = require('../../../../../assets/images/default_resto.png');
const { width } = Dimensions.get('window');
const CARD_WIDTH = width * 0.85;

export function CrousSection({ navigation, userLat, userLon }: { navigation: any, userLat?: number, userLon?: number }) {
    const { themeName } = useContext(AppContext);
    const theme = style.Theme[themeName];

    const [restaurants, setRestaurants] = useState<CrousRestaurant[]>([]);
    const [loading, setLoading] = useState(true);
    const mountedRef = useRef(true);

    const { favorites: favRu, toggleFavorite: toggleFavRu } = useFavorites('crous_favorites');
    const [crousFilter] = useSavedFilter('crous_filter', 'all');

    useEffect(() => {
        mountedRef.current = true;
        if (userLat === undefined || userLon === undefined) return;

        setLoading(true);
        CrousService.fetchRestaurantsBordeaux(userLat, userLon).then(data => {
            if (mountedRef.current) {
                setRestaurants(data);
                setLoading(false);
            }
        }).catch(() => {
            if (mountedRef.current) setLoading(false);
        });
        return () => { mountedRef.current = false; };
    }, [userLat, userLon]);

    const filteredRestaurants = useMemo(() => {
        return [...restaurants].filter(item => {
            if (crousFilter !== 'all') {
                const isRestoU = item.title.includes("Crous Cafet") || item.title.includes("Resto U");
                const isMarket = item.title.includes("Crous Moovy Market") || item.title.includes("Crous Market");

                if (crousFilter === 'resto' && !isRestoU) return false;
                if (crousFilter === 'market' && !isMarket) return false;
            }
            return true;
        }).sort((a, b) => {
            const aFav = favRu.includes(a.id);
            const bFav = favRu.includes(b.id);
            if (aFav && !bFav) return -1;
            if (!aFav && bFav) return 1;
            return (a.distance || 0) - (b.distance || 0);
        });
    }, [restaurants, favRu, crousFilter]);

    const renderCard = ({ item }: { item: CrousRestaurant }) => (
        <Reanimated.View
            entering={FadeIn}
            layout={LinearTransition.springify()}
        >
            <TouchableOpacity
                activeOpacity={0.9}
                onPress={() => navigation.navigate('CrousMenu', {
                    restaurantId: item.id,
                    restaurantName: item.title,
                    location: { lat: item.lat, lon: item.lon }
                })}
                style={{
                    width: CARD_WIDTH,
                    backgroundColor: theme.cardBackground,
                    borderRadius: tokens.radius.xl,
                    marginRight: tokens.space.md,
                    ...tokens.shadow.md,
                    overflow: 'hidden',
                }}
            >
                <View style={{ width: '100%', height: 160, backgroundColor: theme.greyBackground }}>
                    <Image source={defaultRuImage} style={{ position: 'absolute', width: '100%', height: '100%', resizeMode: 'cover' }} />
                    {item.image_url && (
                        <Image source={{ uri: item.image_url }} style={{ position: 'absolute', width: '100%', height: '100%', resizeMode: 'cover' }} />
                    )}
                </View>

                <View style={{ padding: tokens.space.md }}>
                    <View style={{ flexDirection: 'row', alignItems: 'center', marginBottom: tokens.space.xs }}>
                        <Text style={{ fontSize: tokens.fontSize.lg, fontWeight: tokens.fontWeight.bold as any, color: theme.font, flexShrink: 1 }} numberOfLines={1}>
                            {item.title}
                        </Text>
                        <TouchableOpacity onPress={() => toggleFavRu(item.id)} hitSlop={{ top: 15, bottom: 15, left: 10, right: 15 }} style={{ marginLeft: 6 }}>
                            <MaterialCommunityIcons name={favRu.includes(item.id) ? "star" : "star-outline"} size={22} color={favRu.includes(item.id) ? theme.primary : theme.fontSecondary} />
                        </TouchableOpacity>
                    </View>

                    <View style={{ flexDirection: 'row', alignItems: 'center', marginBottom: tokens.space.xs }}>
                        <MaterialIcons name="location-on" size={16} color={theme.fontSecondary} />
                        <Text style={{ fontSize: tokens.fontSize.sm, color: theme.fontSecondary, marginLeft: 4, flex: 1 }} numberOfLines={1}>
                            {item.short_desc}
                        </Text>

                        {item.distance !== undefined && (
                            <View style={{ flexDirection: 'row', alignItems: 'center', backgroundColor: `${theme.primary}15`, paddingHorizontal: tokens.space.sm, paddingVertical: 4, borderRadius: tokens.radius.md }}>
                                <MaterialCommunityIcons name="walk" size={14} color={theme.primary} />
                                <Text style={{ fontSize: tokens.fontSize.sm, fontWeight: tokens.fontWeight.bold as any, color: theme.primary, marginLeft: 4 }}>
                                    {item.distance < 1 ? `${Math.round(item.distance * 1000)} m` : `${item.distance.toFixed(1)} km`}
                                </Text>
                            </View>
                        )}
                    </View>

                    <View style={{ flexDirection: 'row', alignItems: 'flex-start' }}>
                        <MaterialCommunityIcons name="calendar-clock" size={16} color={theme.fontSecondary} style={{ marginTop: 2 }} />
                        <Text style={{ fontSize: tokens.fontSize.sm, color: theme.fontSecondary, marginLeft: 4, flex: 1, lineHeight: 20 }} numberOfLines={2}>
                            {item.opening_desc || Translator.get('UNKNOWN')}
                        </Text>
                    </View>
                </View>
            </TouchableOpacity>
        </Reanimated.View>
    );

    return (
        <View style={{ marginTop: tokens.space.md }}>
            <TouchableOpacity
                style={{ flexDirection: 'row', alignItems: 'center', paddingHorizontal: tokens.space.md, marginBottom: tokens.space.sm }}
                onPress={() => navigation.navigate('Crous')}
                activeOpacity={0.7}
            >
                <Text style={{ fontSize: 22, fontWeight: tokens.fontWeight.bold as any, fontFamily: 'Montserrat_600SemiBold', color: theme.font }}>
                    {Translator.get('RESTAURANT_U') || 'Restaurants Universitaires'}
                </Text>
                <MaterialIcons name="chevron-right" size={26} color={theme.fontSecondary} style={{ marginLeft: 2 }} />
            </TouchableOpacity>

            {loading ? (
                <ActivityIndicator style={{ margin: tokens.space.xl }} color={theme.primary} />
            ) : (
                <FlatList
                    horizontal
                    data={filteredRestaurants}
                    renderItem={renderCard}
                    keyExtractor={item => item.id}
                    showsHorizontalScrollIndicator={false}
                    snapToInterval={CARD_WIDTH + tokens.space.md}
                    decelerationRate="fast"
                    contentContainerStyle={{ paddingHorizontal: tokens.space.md, paddingBottom: tokens.space.lg }}
                />
            )}
        </View>
    );
}

import React, { useEffect, useState, useContext, useRef, useMemo } from 'react';
import { View, Text, FlatList, TouchableOpacity, Image, ActivityIndicator, Dimensions } from 'react-native';
import { MaterialCommunityIcons, MaterialIcons } from '@expo/vector-icons';
import Reanimated, { FadeIn, LinearTransition } from 'react-native-reanimated';

import style, { tokens } from '../../../../shared/theme/Theme';
import { AppContext } from '../../../../shared/services/AppCore';
import Translator from '../../../../shared/i18n/Translator';
import { CampusDataManager as DataManager } from '../../services/CampusDataManager';
import { getDistanceInKm, BuildingInfo } from '../../services/FreeRoomService';
import { useFavorites } from '../../hooks/useFavorites';

const defaultImage = require('../../../../../assets/images/default_resto.png');
const { width } = Dimensions.get('window');
const CARD_WIDTH = width * 0.85;

export function FreeRoomSection({ navigation, userLat, userLon }: { navigation: any, userLat?: number, userLon?: number }) {
    const { themeName } = useContext(AppContext);
    const theme = style.Theme[themeName];

    const [buildings, setBuildings] = useState<BuildingInfo[]>([]);
    const [loading, setLoading] = useState(true);
    const mountedRef = useRef(true);

    const { favorites: favBuildings, toggleFavorite: toggleFavBuilding } = useFavorites('freeroom_favorites');

    useEffect(() => {
        mountedRef.current = true;
        if (userLat === undefined || userLon === undefined) return;

        const loadBuildings = async () => {
            setLoading(true);
            try {
                let bList = DataManager.getBuildingList();
                if (!bList || bList.length === 0) {
                    await DataManager.fetchBuildingList();
                    bList = DataManager.getBuildingList();
                }
                if (mountedRef.current) {
                    if (bList) {
                        bList = (bList as any[]).map(b => {
                            if (userLat !== undefined && userLon !== undefined && b.lat && b.lng) {
                                b.distance = getDistanceInKm(userLat, userLon, b.lat, b.lng);
                            }
                            return b;
                        }) as any;
                    }
                    setBuildings((bList as any) || []);
                    setLoading(false);
                }
            } catch (e) {
                if (mountedRef.current) setLoading(false);
            }
        };

        loadBuildings();
        return () => { mountedRef.current = false; };
    }, [userLat, userLon]);

    const sortedBuildings = useMemo(() => {
        return [...buildings].sort((a, b) => {
            const aFav = favBuildings.includes(a.id);
            const bFav = favBuildings.includes(b.id);
            if (aFav && !bFav) return -1;
            if (!aFav && bFav) return 1;
            return (a.distance || 0) - (b.distance || 0);
        });
    }, [buildings, favBuildings]);

    const renderCard = ({ item }: { item: BuildingInfo }) => {
        const imageSource = item.imageUrl ? { uri: item.imageUrl } : defaultImage;
        const totalRooms = item.rooms ? item.rooms.length : 0;

        let hoursText = Translator.get('UNKNOWN') || 'Non communiqué';
        if (item.schedule) {
            const currentDay = new Date().getDay() || 7; // 1-7
            const daySchedule = item.schedule[String(currentDay)];
            if (daySchedule) {
                hoursText = `${daySchedule.open} - ${daySchedule.close}`;
            } else {
                hoursText = Translator.get('BU_CLOSED') || 'Fermé';
            }
        }

        return (
            <Reanimated.View 
                entering={FadeIn}
                layout={LinearTransition.springify()}
            >
                <TouchableOpacity 
                    activeOpacity={0.9}
                    onPress={() => navigation.navigate('FreeRoomDetails', { building: item })}
                    style={{
                        width: CARD_WIDTH,
                        backgroundColor: theme.cardBackground,
                        borderRadius: tokens.radius.xl, 
                        marginRight: tokens.space.md,
                        ...tokens.shadow.md, 
                        overflow: 'hidden', 
                    }}
                >
                    <Image source={imageSource} style={{ width: '100%', height: 160, resizeMode: 'cover', backgroundColor: theme.greyBackground }} />

                    <View style={{ padding: tokens.space.md }}>
                        <View style={{ flexDirection: 'row', alignItems: 'center', marginBottom: tokens.space.xs }}>
                            <Text style={{ fontSize: tokens.fontSize.lg, fontWeight: tokens.fontWeight.bold as any, color: theme.font, flexShrink: 1 }} numberOfLines={1}>
                                {item.name}
                            </Text>
                            <TouchableOpacity onPress={() => toggleFavBuilding(item.id)} hitSlop={{ top: 15, bottom: 15, left: 10, right: 15 }} style={{ marginLeft: 6 }}>
                                <MaterialCommunityIcons name={favBuildings.includes(item.id) ? "star" : "star-outline"} size={22} color={favBuildings.includes(item.id) ? theme.primary : theme.fontSecondary} />
                            </TouchableOpacity>
                        </View>

                        <View style={{ flexDirection: 'row', alignItems: 'center', marginBottom: tokens.space.xs }}>
                            <MaterialIcons name="location-on" size={16} color={theme.fontSecondary} />
                            <Text style={{ fontSize: tokens.fontSize.sm, color: theme.fontSecondary, marginLeft: 4, flex: 1 }} numberOfLines={1}>
                                {item.campus || 'Talence'}
                            </Text>

                            {item.distance !== undefined && (
                                <View style={{ flexDirection: 'row', alignItems: 'center', backgroundColor: `${theme.primary}15`, paddingHorizontal: tokens.space.sm, paddingVertical: 4, borderRadius: tokens.radius.md }}>
                                    <MaterialCommunityIcons name="walk" size={14} color={theme.primary} />
                                    <Text style={{ fontSize: tokens.fontSize.sm, fontWeight: tokens.fontWeight.bold as any, color: theme.primary, marginLeft: 4 }}>
                                        {item.distance < 1 ? `${Math.round(item.distance * 1000)} m` : `${item.distance.toFixed(1)} km`}
                                    </Text>
                                </View>
                            )}
                        </View>

                        <View style={{ flexDirection: 'row', alignItems: 'center' }}>
                            <MaterialCommunityIcons name="clock-outline" size={16} color={theme.fontSecondary} />
                            <Text style={{ fontSize: tokens.fontSize.sm, color: theme.fontSecondary, marginLeft: 4, flex: 1 }}>
                                {hoursText} • {totalRooms} {Translator.get('ROOMS' as Parameters<typeof Translator.get>[0]) || 'Salles'}
                            </Text>
                        </View>
                    </View>
                </TouchableOpacity>
            </Reanimated.View>
        );
    };

    return (
        <View style={{ marginTop: tokens.space.md }}>
            <TouchableOpacity
                style={{ flexDirection: 'row', alignItems: 'center', paddingHorizontal: tokens.space.md, marginBottom: tokens.space.sm }}
                onPress={() => navigation.navigate('FreeRoomScreen')} // Wait, navigation key in Dashboard was 'FreeRoomScreen'? 
                // Let's keep it 'FreeRoomScreen' to match original file
                activeOpacity={0.7}
            >
                <Text style={{ fontSize: 22, fontWeight: tokens.fontWeight.bold as any, fontFamily: 'Montserrat_600SemiBold', color: theme.font }}>
                    {Translator.get('FREE_ROOMS') || 'Salles Libres'}
                </Text>
                <MaterialIcons name="chevron-right" size={26} color={theme.fontSecondary} style={{ marginLeft: 2 }} />
            </TouchableOpacity>

            {loading ? (
                <ActivityIndicator style={{ margin: tokens.space.xl }} color={theme.primary} />
            ) : (
                <FlatList
                    horizontal
                    data={sortedBuildings}
                    renderItem={renderCard}
                    keyExtractor={item => item.id}
                    showsHorizontalScrollIndicator={false}
                    snapToInterval={CARD_WIDTH + tokens.space.md}
                    decelerationRate="fast"
                    contentContainerStyle={{ paddingHorizontal: tokens.space.md, paddingBottom: tokens.space.lg }}
                />
            )}
        </View>
    );
}

import React, { useEffect, useState, useContext, useRef, useMemo } from 'react';
import { View, Text, FlatList, TouchableOpacity, Image, ActivityIndicator, Dimensions } from 'react-native';
import { MaterialCommunityIcons, MaterialIcons } from '@expo/vector-icons';
import Reanimated, { FadeIn, LinearTransition } from 'react-native-reanimated';

import style, { tokens } from '../../../../shared/theme/Theme';
import { AppContext } from '../../../../shared/services/AppCore';
import Translator from '../../../../shared/i18n/Translator';
import LibraryService, { LibraryInfo, AffluencesData } from '../../services/LibraryService';
import { useFavorites } from '../../hooks/useFavorites';
import { useSavedFilter } from '../../hooks/useSavedFilter';

const defaultBuImage = require('../../../../../assets/images/default_resto.png');
const { width } = Dimensions.get('window');
const CARD_WIDTH = width * 0.85;

export function LibrarySection({ navigation, userLat, userLon }: { navigation: any, userLat?: number, userLon?: number }) {
    const { themeName } = useContext(AppContext);
    const theme = style.Theme[themeName];

    const [libraries, setLibraries] = useState<LibraryInfo[]>([]);
    const [affluences, setAffluences] = useState<Record<string, AffluencesData>>({});
    const [loading, setLoading] = useState(true);
    const mountedRef = useRef(true);

    const { favorites: favBu, toggleFavorite: toggleFavBu } = useFavorites('library_favorites');
    const [libraryFilter] = useSavedFilter('library_filter', 'all');

    useEffect(() => {
        mountedRef.current = true;
        if (userLat === undefined || userLon === undefined) return;

        const loadBu = async () => {
            setLoading(true);
            try {
                const buData = await LibraryService.fetchNearbyLibraries(userLat, userLon);
                if (!mountedRef.current) return;
                setLibraries(buData);
                setLoading(false);

                const newAffluences: Record<string, AffluencesData> = {};
                const promises = buData.map(lib =>
                    LibraryService.getAffluencesData(lib.slug)
                        .then(res => { if (res) newAffluences[lib.id] = res; })
                        .catch(() => { })
                );
                await Promise.all(promises);
                if (mountedRef.current) setAffluences(newAffluences);
            } catch (e) {
                if (mountedRef.current) setLoading(false);
            }
        };

        loadBu();
        return () => { mountedRef.current = false; };
    }, [userLat, userLon]);

    const filteredLibraries = useMemo(() => {
        return [...libraries].filter(item => {
            if (libraryFilter === 'open') {
                const affluenceData = affluences[item.id];
                const isOpen = affluenceData?.isOpen ?? true;
                if (!isOpen) return false;
            }
            return true;
        }).sort((a, b) => {
            const aFav = favBu.includes(a.id);
            const bFav = favBu.includes(b.id);
            if (aFav && !bFav) return -1;
            if (!aFav && bFav) return 1;
            return (a.distance || 0) - (b.distance || 0);
        });
    }, [libraries, favBu, libraryFilter, affluences]);

    const renderCard = ({ item }: { item: LibraryInfo }) => {
        const affluenceData = affluences[item.id];
        const rate = affluenceData?.occupancyRate ?? null;
        const isOpen = affluenceData?.isOpen ?? true;

        let statusColor = '#f44336';
        if (isOpen) {
            if (rate === null || rate < 50) statusColor = '#4caf50';
            else if (rate < 80) statusColor = '#ff9800';
            else statusColor = '#ff4436';
        }

        let statusText = isOpen ? (Translator.get('BU_OPEN') || 'Ouvert') : (Translator.get('BU_CLOSED') || 'Fermé');
        if (!isOpen && affluenceData?.openingText) {
            statusText = `${statusText} - ${affluenceData.openingText}`;
        }

        const imageSource = item.imageUrl ? { uri: item.imageUrl } : defaultBuImage;

        return (
            <Reanimated.View
                entering={FadeIn}
                layout={LinearTransition.springify()}
            >
                <TouchableOpacity
                    activeOpacity={0.9}
                    onPress={() => navigation.navigate('LibraryDetails', { library: item, affluence: affluenceData })}
                    style={{
                        width: CARD_WIDTH,
                        backgroundColor: theme.cardBackground,
                        borderRadius: tokens.radius.xl,
                        marginRight: tokens.space.md,
                        ...tokens.shadow.md,
                        overflow: 'hidden',
                    }}
                >
                    <Image source={imageSource} style={{ width: '100%', height: 160, resizeMode: 'cover', backgroundColor: theme.greyBackground }} />

                    <View style={{ padding: tokens.space.md }}>
                        <View style={{ flexDirection: 'row', alignItems: 'center', marginBottom: tokens.space.xs }}>
                            <Text style={{ fontSize: tokens.fontSize.lg, fontWeight: tokens.fontWeight.bold as any, color: theme.font, flexShrink: 1 }} numberOfLines={1}>
                                {item.name}
                            </Text>
                            <TouchableOpacity onPress={() => toggleFavBu(item.id)} hitSlop={{ top: 15, bottom: 15, left: 10, right: 15 }} style={{ marginLeft: 6 }}>
                                <MaterialCommunityIcons name={favBu.includes(item.id) ? "star" : "star-outline"} size={22} color={favBu.includes(item.id) ? theme.primary : theme.fontSecondary} />
                            </TouchableOpacity>
                        </View>

                        <View style={{ flexDirection: 'row', alignItems: 'center', marginBottom: tokens.space.xs }}>
                            <MaterialIcons name="location-on" size={16} color={theme.fontSecondary} />
                            <Text style={{ fontSize: tokens.fontSize.sm, color: theme.fontSecondary, marginLeft: 4, flex: 1 }} numberOfLines={1}>
                                {item.campus}
                            </Text>

                            {item.distance !== undefined && (
                                <View style={{ flexDirection: 'row', alignItems: 'center', backgroundColor: `${theme.primary}15`, paddingHorizontal: tokens.space.sm, paddingVertical: 4, borderRadius: tokens.radius.md }}>
                                    <MaterialIcons name="directions-walk" size={14} color={theme.primary} />
                                    <Text style={{ fontSize: tokens.fontSize.sm, fontWeight: tokens.fontWeight.bold as any, color: theme.primary, marginLeft: 4 }}>
                                        {item.distance < 1 ? `${Math.round(item.distance * 1000)} m` : `${item.distance.toFixed(1)} km`}
                                    </Text>
                                </View>
                            )}
                        </View>

                        <View style={{ flexDirection: 'row', alignItems: 'center' }}>
                            <MaterialCommunityIcons name={isOpen ? 'door-open' : 'door-closed'} size={16} color={statusColor} />
                            <Text numberOfLines={1} style={{ fontSize: tokens.fontSize.sm, fontWeight: tokens.fontWeight.semibold as any, color: statusColor, marginLeft: 4, flexShrink: 1 }}>
                                {statusText}
                            </Text>

                            {isOpen && rate !== null && (
                                <>
                                    <View style={{ flex: 1, height: 6, backgroundColor: theme.greyBackground, borderRadius: 3, overflow: 'hidden', marginHorizontal: tokens.space.sm }}>
                                        <View style={{ width: `${rate}%`, height: '100%', backgroundColor: statusColor, borderRadius: 3 }} />
                                    </View>
                                    <Text style={{ fontSize: tokens.fontSize.xs, color: theme.fontSecondary, fontWeight: tokens.fontWeight.bold as any }}>
                                        {`${rate}%`}
                                    </Text>
                                </>
                            )}
                        </View>
                    </View>
                </TouchableOpacity>
            </Reanimated.View>
        );
    };

    return (
        <View style={{ marginTop: tokens.space.md }}>
            <TouchableOpacity
                style={{ flexDirection: 'row', alignItems: 'center', paddingHorizontal: tokens.space.md, marginBottom: tokens.space.sm }}
                onPress={() => navigation.navigate('Library')}
                activeOpacity={0.7}
            >
                <Text style={{ fontSize: 22, fontWeight: tokens.fontWeight.bold as any, fontFamily: 'Montserrat_600SemiBold', color: theme.font }}>
                    {Translator.get('UNIVERSITY_LIBRARY') || 'Bibliothèques Universitaires'}
                </Text>
                <MaterialIcons name="chevron-right" size={26} color={theme.fontSecondary} style={{ marginLeft: 2 }} />
            </TouchableOpacity>

            {loading ? (
                <ActivityIndicator style={{ margin: tokens.space.xl }} color={theme.primary} />
            ) : (
                <FlatList
                    horizontal
                    data={filteredLibraries}
                    renderItem={renderCard}
                    keyExtractor={item => item.id}
                    showsHorizontalScrollIndicator={false}
                    snapToInterval={CARD_WIDTH + tokens.space.md}
                    decelerationRate="fast"
                    contentContainerStyle={{ paddingHorizontal: tokens.space.md, paddingBottom: tokens.space.lg }}
                />
            )}
        </View>
    );
}

import React, { useEffect, useState, useContext, useRef } from 'react';
import { View, Text, ScrollView, ActivityIndicator, TouchableOpacity, FlatList } from 'react-native';
import { SafeAreaView, useSafeAreaInsets } from 'react-native-safe-area-context';
import { MaterialCommunityIcons } from '@expo/vector-icons';
import moment from 'moment';

import style, { tokens } from '../../../shared/theme/Theme';
import { AppContext } from '../../../shared/services/AppCore';
import Translator from '../../../shared/i18n/Translator';
import { BuildingInfo, FreeRoomSlot, RoomInfo } from '../services/FreeRoomService';
import { CampusApiService as FetchManager } from '../services/CampusApiService';

export default function FreeRoomDetailsScreen({ route, navigation }: any) {
    const { building } = route.params as { building: BuildingInfo };
    const AppContextValues = useContext(AppContext) as any;
    const theme = style.Theme[AppContextValues.themeName];
    const insets = useSafeAreaInsets();

    const [loading, setLoading] = useState(true);
    const [selectedIndex, setSelectedIndex] = useState(0);
    const [freeRooms, setFreeRooms] = useState<FreeRoomSlot[]>([]);
    const [allEvents, setAllEvents] = useState<any[]>([]);

    const [isClosed, setIsClosed] = useState(false);
    const [hoursList, setHoursList] = useState<string[]>([]);
    const [buildingCloseTime, setBuildingCloseTime] = useState('20:00');

    const flatListRef = useRef<FlatList>(null);
    const mountedRef = useRef(true);
    const scrollTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

    useEffect(() => {
        return () => {
            mountedRef.current = false;
            if (scrollTimeoutRef.current) clearTimeout(scrollTimeoutRef.current);
        };
    }, []);

    useEffect(() => {
        navigation.setOptions({
            headerTitle: () => (
                <Text style={{ color: theme.primary, fontSize: tokens.fontSize.xl, fontWeight: tokens.fontWeight.bold as any }}>
                    {Translator.get('DETAILS') || 'Détails'}
                </Text>
            ),
            headerTitleAlign: 'center'
        });
    }, [navigation, theme]);

    useEffect(() => {
        let closed = false;
        const currentDay = new Date().getDay() || 7;
        const daySchedule = building.schedule ? building.schedule[String(currentDay)] : null;

        if (!daySchedule) {
            closed = true;
        } else {
            setBuildingCloseTime(daySchedule.close);
            const openTime = parseInt(daySchedule.open.split(':')[0]);
            let closeTime = parseInt(daySchedule.close.split(':')[0]);

            if (daySchedule.close.includes(':00')) {
                closeTime -= 1;
            }

            const list = [];
            for (let i = openTime; i <= closeTime; i++) {
                list.push(`${i.toString().padStart(2, '0')}:00`);
            }
            setHoursList(list);

            const currentHour = new Date().getHours();
            let defaultIndex = list.findIndex(h => parseInt(h.split(':')[0]) === currentHour);
            if (defaultIndex === -1) {
                defaultIndex = currentHour < openTime ? 0 : list.length - 1;
            }
            setSelectedIndex(defaultIndex);
        }

        setIsClosed(closed);
        loadSchedules();
    }, []);

    const loadSchedules = async () => {
        setLoading(true);
        const today = moment().format('YYYY-MM-DD');

        const promises = building.rooms.map(async (room) => {
            try {
                const res = await FetchManager.fetchRoomsScheduleDay([room.id], today);
                return { roomId: room.id, events: res || [] };
            } catch (e) {
                return { roomId: room.id, events: [] };
            }
        });

        const results = await Promise.all(promises);

        if (!mountedRef.current) return;
        setAllEvents(results);
        setLoading(false);
    };

    useEffect(() => {
        if (!loading && allEvents && allEvents.length > 0) {
            if (allEvents.some(r => r.events.some((e: any) => e.isVacances))) {
                setIsClosed(true);
            } else if (!isClosed && hoursList.length > 0) {
                computeFreeRooms();
            }
        }
    }, [selectedIndex, loading, allEvents, isClosed, hoursList]);

    useEffect(() => {
        if (hoursList.length > 0 && flatListRef.current && !loading) {
            const timerId = setTimeout(() => {
                flatListRef.current?.scrollToIndex({
                    index: selectedIndex,
                    animated: true,
                    viewPosition: 0.5
                });
            }, 100);
            return () => clearTimeout(timerId);
        }
    }, [selectedIndex, loading]);

    const computeFreeRooms = () => {
        if (hoursList.length === 0 || selectedIndex >= hoursList.length) return;

        const selectedHourStr = hoursList[selectedIndex];
        const selectedTime = moment(selectedHourStr, 'HH:mm');
        const endOfDayTime = moment(buildingCloseTime, 'HH:mm');

        const availableSlots: FreeRoomSlot[] = [];

        for (const room of building.rooms) {
            const roomResult = allEvents.find(r => r.roomId === room.id);
            const roomEvents = roomResult ? roomResult.events : [];

            let isOccupied = false;
            let nextEventStart = endOfDayTime;

            for (const event of roomEvents) {
                const eventStart = moment(event.starttime, 'HH:mm');
                const eventEnd = moment(event.endtime, 'HH:mm');

                // Si l'heure sélectionnée tombe pendant un cours
                if (selectedTime.isSameOrAfter(eventStart) && selectedTime.isBefore(eventEnd)) {
                    isOccupied = true;
                    break;
                }

                // Si l'évènement est dans le futur par rapport à l'heure sélectionnée
                if (eventStart.isAfter(selectedTime)) {
                    if (eventStart.isBefore(nextEventStart)) {
                        nextEventStart = eventStart;
                    }
                }
            }

            if (!isOccupied) {
                const durationMinutes = nextEventStart.diff(selectedTime, 'minutes');
                // N'inclure que s'il reste au moins 15 min de libre
                if (durationMinutes >= 15) {
                    availableSlots.push({
                        room,
                        availableUntil: nextEventStart.format('HH:mm'),
                        durationMinutes
                    });
                }
            }
        }

        // Trier par durée de disponibilité (plus long en premier), puis par nom
        availableSlots.sort((a, b) => {
            if (b.durationMinutes !== a.durationMinutes) {
                return b.durationMinutes - a.durationMinutes;
            }
            return a.room.name.localeCompare(b.room.name);
        });

        setFreeRooms(availableSlots);
    };

    if (loading) {
        return (
            <SafeAreaView edges={['left', 'right']} style={{ flex: 1, backgroundColor: theme.courseBackground }}>
                <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
                    <ActivityIndicator size="large" color={theme.accent ?? theme.primary} />
                </View>
            </SafeAreaView>
        );
    }

    return (
        <SafeAreaView edges={['left', 'right']} style={{ flex: 1, backgroundColor: theme.courseBackground }}>

            {isClosed ? (
                <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center', padding: tokens.space.xl }}>
                    <MaterialCommunityIcons name="door-closed-lock" size={64} color={theme.fontSecondary} />
                    <Text style={{ marginTop: tokens.space.md, fontSize: tokens.fontSize.lg, color: theme.fontSecondary, textAlign: 'center' }}>
                        {Translator.get('BU_CLOSED') || 'Bâtiment fermé aujourd\'hui'}
                    </Text>
                </View>
            ) : (
                <>
                    {/* ── Bandeau des heures défilant horizontalement ── */}
                    <View style={{ backgroundColor: theme.cardBackground, borderBottomWidth: 1, borderBottomColor: theme.border, paddingVertical: tokens.space.sm, paddingTop: (insets.top || 0) + 65 }}>

                        <Text 
                            style={{
                                fontSize: tokens.fontSize.xl,
                                fontWeight: tokens.fontWeight.bold as any,
                                color: theme.fontSecondary,
                                textAlign: 'left',
                                paddingHorizontal: tokens.space.md,
                                marginBottom: tokens.space.md,
                            }} 
                            numberOfLines={1}
                        >
                            {building.name}
                        </Text>

                        <FlatList
                            ref={flatListRef}
                            horizontal
                            showsHorizontalScrollIndicator={false}
                            data={hoursList}
                            keyExtractor={(item) => item}
                            contentContainerStyle={{ paddingHorizontal: tokens.space.sm }}
                            onScrollToIndexFailed={(info) => {
                                scrollTimeoutRef.current = setTimeout(() => {
                                    flatListRef.current?.scrollToIndex({ index: info.index, animated: true, viewPosition: 0.5 });
                                }, 500);
                            }}
                            renderItem={({ item, index }) => {
                                const isSelected = index === selectedIndex;
                                const primaryColor = theme.accent ?? theme.primary;

                                return (
                                    <TouchableOpacity 
                                        onPress={() => setSelectedIndex(index)}
                                        style={{
                                            paddingHorizontal: tokens.space.md,
                                            paddingVertical: tokens.space.sm,
                                            marginHorizontal: tokens.space.xs,
                                            borderRadius: tokens.radius.md,
                                            backgroundColor: theme.greyBackground,
                                            borderWidth: 2,
                                            borderColor: isSelected ? primaryColor : 'transparent',
                                        }}
                                    >
                                        <Text style={{ 
                                            color: isSelected ? primaryColor : theme.fontSecondary,
                                            fontWeight: isSelected ? (tokens.fontWeight.bold as any) : (tokens.fontWeight.medium as any),
                                            fontSize: tokens.fontSize.sm
                                        }}>
                                            {item}
                                        </Text>
                                    </TouchableOpacity>
                                );
                            }}
                        />
                    </View>

                    {/* ── Liste des salles libres ── */}
                    <ScrollView style={{ flex: 1, paddingTop: tokens.space.md, paddingHorizontal: tokens.space.md }}>
                        <View style={{ flexDirection: 'row', alignItems: 'center', marginTop: tokens.space.sm, marginBottom: tokens.space.md }}>
                            <MaterialCommunityIcons 
                                name="door-open" 
                                size={20} 
                                color={theme.accent ?? theme.primary} 
                            />
                            <Text style={{ fontSize: tokens.fontSize.lg, fontWeight: tokens.fontWeight.bold as any, color: theme.font, marginLeft: tokens.space.sm }}>
                                {Translator.get('FREE_ROOMS') || 'Salles libres'} ({freeRooms.length})
                            </Text>
                        </View>

                        {freeRooms.length === 0 ? (
                            <Text style={{ textAlign: 'center', color: theme.fontSecondary, marginTop: tokens.space.xl }}>
                                {Translator.get('NO_FREE_ROOMS' as Parameters<typeof Translator.get>[0]) || 'Aucune salle libre à cette heure.'}
                            </Text>
                        ) : (
                            freeRooms.map((slot, index) => (
                                <View key={index} style={[style.course.card as any, { 
                                    backgroundColor: theme.cardBackground, 
                                    borderColor: theme.border, 
                                    borderWidth: 1,
                                    flexDirection: 'row',
                                    alignItems: 'center',
                                    padding: tokens.space.md,
                                    marginBottom: tokens.space.sm
                                }]}>
                                    <View style={{ flex: 1 }}>
                                        <Text style={{ fontSize: tokens.fontSize.md, fontWeight: tokens.fontWeight.semibold as any, color: theme.accent ?? theme.primary, marginBottom: 2 }}>
                                            {slot.room.name}
                                        </Text>
                                        <Text style={{ fontSize: tokens.fontSize.sm, color: theme.fontSecondary }}>
                                            {Translator.get('AVAILABLE_UNTIL') || 'Libre jusqu\'à'} {slot.availableUntil}
                                        </Text>
                                    </View>
                                    <View style={{ backgroundColor: `${theme.primary}15`, paddingHorizontal: tokens.space.sm, paddingVertical: 4, borderRadius: tokens.radius.md }}>
                                        <Text style={{ fontSize: tokens.fontSize.sm, fontWeight: tokens.fontWeight.bold as any, color: theme.primary }}>
                                            {Math.floor(slot.durationMinutes / 60)}h{slot.durationMinutes % 60 > 0 ? (slot.durationMinutes % 60).toString().padStart(2, '0') : ''}
                                        </Text>
                                    </View>
                                </View>
                            ))
                        )}

                        <View style={{ height: tokens.space.xxl }} />
                    </ScrollView>
                </>
            )}

        </SafeAreaView>
    );
}

import React, { useState, useEffect, useContext, useMemo } from 'react';
import { View, Text } from 'react-native';
import { MaterialCommunityIcons, MaterialIcons } from '@expo/vector-icons';

import { AppContext } from '../../../shared/services/AppCore';
import style, { tokens } from '../../../shared/theme/Theme';
import Translator from '../../../shared/i18n/Translator';
import { CampusDataManager as DataManager } from '../services/CampusDataManager';
import { BuildingInfo, getDistanceInKm } from '../services/FreeRoomService';
import { withHeaderAnimation } from '../../../shared/navigation/NavHelpers';

import { CampusListLayout } from '../components/CampusListLayout';
import { CampusCard } from '../components/CampusCard';
import { useFavorites } from '../hooks/useFavorites';
import { useCampusLocation } from '../hooks/useCampusLocation';

function FreeRoomScreen({ navigation, onAnimatedScroll }: any) {
    const AppContextValues = useContext(AppContext) as any;
    const themeName = AppContextValues.themeName ?? 'light';
    const theme = style.Theme[themeName];

    const { fetchLocation } = useCampusLocation();
    const { favorites, toggleFavorite } = useFavorites('freeroom_favorites');

    const [buildings, setBuildings] = useState<BuildingInfo[]>([]);
    const [loading, setLoading] = useState<boolean>(true);
    const [searchText, setSearchText] = useState('');

    useEffect(() => {
        let mounted = true;
        const loadBuildings = async () => {
            setLoading(true);
            try {
                let bList = DataManager.getBuildingList();
                if (!bList || bList.length === 0) {
                    await DataManager.fetchBuildingList();
                    bList = DataManager.getBuildingList();
                }

                if (mounted) {
                    const { lat, lon } = await fetchLocation();

                    if (bList) {
                        bList = (bList as any[]).map((b: BuildingInfo) => {
                            if (lat !== undefined && lon !== undefined && b.lat && b.lng) {
                                b.distance = getDistanceInKm(lat, lon, b.lat, b.lng);
                            }
                            return b;
                        }) as any;
                    }

                    setBuildings(bList as any || []);
                }
            } catch (error) {
                console.error(error);
            } finally {
                if (mounted) setLoading(false);
            }
        };

        loadBuildings();
        return () => { mounted = false; };
    }, [fetchLocation]);

    const filteredData = useMemo(() => {
        let result = [...buildings].sort((a, b) => {
            const aFav = favorites.includes(a.id);
            const bFav = favorites.includes(b.id);
            if (aFav && !bFav) return -1;
            if (!aFav && bFav) return 1;
            return (a.distance || 0) - (b.distance || 0);
        });

        if (searchText.trim().length > 0) {
            const query = searchText.toLowerCase().trim();
            result = result.filter(item => {
                const matchName = item.name.toLowerCase().includes(query);
                const matchCity = item.campus && item.campus.toLowerCase().includes(query);
                return matchName || matchCity;
            });
        }

        return result;
    }, [buildings, favorites, searchText]);

    const renderItem = ({ item }: { item: BuildingInfo }) => {
        const totalRooms = item.rooms ? item.rooms.length : 0;

        let hoursText = Translator.get('UNKNOWN') || 'Non communiqué';
        if (item.schedule) {
            const currentDay = new Date().getDay() || 7;
            const daySchedule = item.schedule[String(currentDay)];
            if (daySchedule) {
                hoursText = `${daySchedule.open} - ${daySchedule.close}`;
            } else {
                hoursText = Translator.get('BU_CLOSED') || 'Fermé';
            }
        }

        return (
            <CampusCard
                title={item.name}
                imageUrl={item.imageUrl}
                isFavorite={favorites.includes(item.id)}
                onToggleFavorite={() => toggleFavorite(item.id)}
                onPress={() => navigation.navigate('FreeRoomDetails', { building: item })}
            >
                <View style={{ flexDirection: 'row', alignItems: 'center', marginBottom: tokens.space.xs }}>
                    <MaterialIcons name="location-on" size={16} color={theme.fontSecondary} />
                    <Text style={{ fontSize: tokens.fontSize.sm, color: theme.fontSecondary, marginLeft: 4, flex: 1 }} numberOfLines={1}>
                        {item.campus || 'Talence'}
                    </Text>

                    {item.distance !== undefined && (
                        <View style={{ flexDirection: 'row', alignItems: 'center', backgroundColor: `${theme.primary}15`, paddingHorizontal: tokens.space.sm, paddingVertical: 4, borderRadius: tokens.radius.md }}>
                            <MaterialCommunityIcons name="walk" size={14} color={theme.primary} />
                            <Text style={{ fontSize: tokens.fontSize.sm, fontWeight: tokens.fontWeight.bold as any, color: theme.primary, marginLeft: 4 }}>
                                {item.distance < 1 ? `${Math.round(item.distance * 1000)} m` : `${item.distance.toFixed(1)} km`}
                            </Text>
                        </View>
                    )}
                </View>

                <View style={{ flexDirection: 'row', alignItems: 'center' }}>
                    <MaterialCommunityIcons name="clock-outline" size={16} color={theme.fontSecondary} />
                    <Text style={{ fontSize: tokens.fontSize.sm, color: theme.fontSecondary, marginLeft: 4, flex: 1 }}>
                        {hoursText} • {totalRooms} {Translator.get('ROOMS' as Parameters<typeof Translator.get>[0]) || 'Salles'}
                    </Text>
                </View>
            </CampusCard>
        );
    };

    return (
        <CampusListLayout
            data={filteredData}
            loading={loading}
            renderItem={renderItem}
            onAnimatedScroll={onAnimatedScroll}
            navigation={navigation}

            hasSearch={true}
            searchText={searchText}
            onSearchChange={setSearchText}
            searchPlaceholder={Translator.get('SEARCH_BUILDING' as Parameters<typeof Translator.get>[0]) || 'Rechercher un bâtiment...'}

            emptyIcon="domain"
            emptyMessage={Translator.get('NO_BUILDING_FOUND' as Parameters<typeof Translator.get>[0]) || 'Aucun bâtiment trouvé'}
        />
    );
}

