import React, { useState, useEffect, useContext, useMemo } from 'react';
import { View, Text } from 'react-native';
import { MaterialCommunityIcons, MaterialIcons } from '@expo/vector-icons';

import { AppContext } from '../../../shared/services/AppCore';
import style, { tokens } from '../../../shared/theme/Theme';
import Translator from '../../../shared/i18n/Translator';
import LibraryService, { LibraryInfo, AffluencesData } from '../services/LibraryService';
import { withHeaderAnimation } from '../../../shared/navigation/NavHelpers';

import { CampusListLayout } from '../components/CampusListLayout';
import { CampusCard } from '../components/CampusCard';
import { useFavorites } from '../hooks/useFavorites';
import { useCampusLocation } from '../hooks/useCampusLocation';
import { useSavedFilter } from '../hooks/useSavedFilter';

function LibraryScreen({ navigation, onAnimatedScroll }: any) {
    const AppContextValues = useContext(AppContext) as { themeName: 'light' | 'dark' };
    const themeName = AppContextValues.themeName ?? 'light';
    const theme = style.Theme[themeName];

    const { fetchLocation } = useCampusLocation();
    const { favorites, toggleFavorite } = useFavorites('library_favorites');
    const [selectedFilter, setSelectedFilter] = useSavedFilter('library_filter', 'all');

    const [searchText, setSearchText] = useState('');
    const [libraries, setLibraries] = useState<LibraryInfo[]>([]);
    const [affluences, setAffluences] = useState<Record<string, AffluencesData>>({});
    const [loading, setLoading] = useState<boolean>(true);

    useEffect(() => {
        let mounted = true;
        const loadLibraries = async () => {
            setLoading(true);
            try {
                const { lat, lon } = await fetchLocation();

                const nearbyLibs = await LibraryService.fetchNearbyLibraries(lat, lon);
                if (!mounted) return;
                setLibraries(nearbyLibs);

                const affluencesPromises = nearbyLibs.map(async (lib) => {
                    const data = await LibraryService.getAffluencesData(lib.slug);
                    return { id: lib.id, data };
                });

                const results = await Promise.all(affluencesPromises);
                if (!mounted) return;

                const newAffluences: Record<string, AffluencesData> = {};
                results.forEach(res => {
                    if (res.data) newAffluences[res.id] = res.data;
                });
                setAffluences(newAffluences);
            } catch (error) {
                console.error("Erreur critique dans loadLibraries:", error);
            } finally {
                if (mounted) setLoading(false);
            }
        };

        loadLibraries();
        return () => { mounted = false; };
    }, [fetchLocation]);

    const filteredData = useMemo(() => {
        let result = [...libraries].sort((a, b) => {
            const aFav = favorites.includes(a.id);
            const bFav = favorites.includes(b.id);
            if (aFav && !bFav) return -1;
            if (!aFav && bFav) return 1;
            return (a.distance || 0) - (b.distance || 0);
        });

        return result.filter(item => {
            if (selectedFilter === 'open') {
                const isOpen = affluences[item.id]?.isOpen ?? true; 
                if (!isOpen) return false;
            }

            if (searchText.trim().length > 0) {
                const query = searchText.toLowerCase().trim();
                const matchName = item.name.toLowerCase().includes(query);
                const matchCity = item.campus && item.campus.toLowerCase().includes(query);
                if (!matchName && !matchCity) return false;
            }

            return true;
        });
    }, [libraries, favorites, searchText, selectedFilter, affluences]);

    const filterOptions = [
        { id: 'all', label: Translator.get('ALL_LIBRARIES' as Parameters<typeof Translator.get>[0]) },
        { id: 'open', label: Translator.get('OPEN_LIBRARIES' as Parameters<typeof Translator.get>[0]) }
    ];

    const renderItem = ({ item }: { item: LibraryInfo }) => {
        const affluenceData = affluences[item.id];
        const rate = affluenceData?.occupancyRate ?? null;
        const isOpen = affluenceData?.isOpen ?? true; 

        let statusColor = '#f44336';
        if (isOpen) {
            if (rate === null || rate < 50) statusColor = '#4caf50';
            else if (rate < 80) statusColor = '#ff9800';
            else statusColor = '#ff4436';
        }

        let statusText = isOpen ? (Translator.get('BU_OPEN')) : (Translator.get('BU_CLOSED'));
        if (!isOpen && affluenceData?.openingText) { 
            statusText = `${statusText} - ${affluenceData.openingText}`;
        }

        return (
            <CampusCard
                title={item.name}
                imageUrl={item.imageUrl}
                isFavorite={favorites.includes(item.id)}
                onToggleFavorite={() => toggleFavorite(item.id)}
                onPress={() => navigation.navigate('LibraryDetails', { library: item, affluence: affluenceData })}
            >
                {/* Ligne : Ville + Badge de Distance */}
                <View style={{ flexDirection: 'row', alignItems: 'center', marginBottom: tokens.space.xs }}>
                    <MaterialIcons name="location-on" size={16} color={theme.fontSecondary} />
                    <Text style={{ fontSize: tokens.fontSize.sm, color: theme.fontSecondary, marginLeft: 4, flex: 1 }}>
                        {item.campus}
                    </Text>

                    {item.distance !== undefined && (
                        <View style={{
                            flexDirection: 'row',
                            alignItems: 'center',
                            backgroundColor: `${theme.primary}15`, 
                            paddingHorizontal: tokens.space.sm,
                            paddingVertical: 4,
                            borderRadius: tokens.radius.md,
                        }}>
                            <MaterialIcons name="directions-walk" size={14} color={theme.primary} />
                            <Text style={{
                                fontSize: tokens.fontSize.sm,
                                fontWeight: tokens.fontWeight.bold as never,
                                color: theme.primary,
                                marginLeft: 4
                            }}>
                                {item.distance < 1 
                                    ? `${Math.round(item.distance * 1000)} m` 
                                    : `${item.distance.toFixed(1)} km`}
                            </Text>
                        </View>
                    )}
                </View>

                {/* Jauge d'affluence en une ligne */}
                <View style={{ flexDirection: 'row', alignItems: 'center' }}>
                    <MaterialCommunityIcons name={isOpen ? 'door-open' : 'door-closed'} size={16} color={statusColor} />
                    <Text numberOfLines={1} style={{ fontSize: tokens.fontSize.sm, fontWeight: tokens.fontWeight.semibold as never, color: statusColor, marginLeft: 4, flexShrink: 1 }}>
                        {statusText}
                    </Text>

                    {isOpen && rate !== null && (
                        <>
                            <View style={{ flex: 1, height: 6, backgroundColor: theme.greyBackground, borderRadius: 3, overflow: 'hidden', marginHorizontal: tokens.space.sm }}>
                                <View style={{ width: `${rate}%`, height: '100%', backgroundColor: statusColor, borderRadius: 3 }} />
                            </View>
                            <Text style={{ fontSize: tokens.fontSize.xs, color: theme.fontSecondary, fontWeight: tokens.fontWeight.bold as never }}>
                                {`${rate}%`}
                            </Text>
                        </>
                    )}
                </View>
            </CampusCard>
        );
    };

    return (
        <CampusListLayout
            data={filteredData}
            loading={loading}
            renderItem={renderItem}
            onAnimatedScroll={onAnimatedScroll}
            navigation={navigation}

            hasSearch={true}
            searchText={searchText}
            onSearchChange={setSearchText}
            searchPlaceholder={Translator.get('SEARCH_BU_CITY' as Parameters<typeof Translator.get>[0])}

            filterOptions={filterOptions}
            selectedFilter={selectedFilter}
            onFilterChange={setSelectedFilter}

            emptyIcon="bookshelf"
            emptyMessage={Translator.get('NO_BU_NEARBY')}
        />
    );
}

export default withHeaderAnimation(LibraryScreen);

import React, { useContext, useEffect, useState } from 'react';
import { Animated, View, Text, ActivityIndicator, KeyboardAvoidingView, Platform, TextInput, TouchableOpacity, Modal, TouchableWithoutFeedback } from 'react-native';
import { SafeAreaView, useSafeAreaInsets } from 'react-native-safe-area-context';
import { MaterialCommunityIcons, MaterialIcons } from '@expo/vector-icons';
import { useRoute } from '@react-navigation/native';

import style, { tokens } from '../../../shared/theme/Theme';
import { AppContext } from '../../../shared/services/AppCore';
import Translator from '../../../shared/i18n/Translator';
import { globalScrollValues } from '../../../shared/navigation/NavHelpers';

export interface FilterOption {
    id: string;
    label: string;
}

export interface CampusListLayoutProps<T> {
    data: T[];
    loading: boolean;
    renderItem: (info: { item: T }) => React.ReactElement;
    onAnimatedScroll?: any;

    // Search
    hasSearch?: boolean;
    searchText?: string;
    onSearchChange?: (text: string) => void;
    searchPlaceholder?: string;

    // Filters
    filterOptions?: FilterOption[];
    selectedFilter?: string;
    onFilterChange?: (id: string) => void;

    // Empty State
    emptyIcon?: any; // MaterialCommunityIcons name
    emptyMessage?: string;

    // Navigation for setting header filter icon
    navigation?: any;
}

export function CampusListLayout<T>({
    data,
    loading,
    renderItem,
    onAnimatedScroll,
    hasSearch = false,
    searchText = '',
    onSearchChange,
    searchPlaceholder = 'Rechercher...',
    filterOptions = [],
    selectedFilter,
    onFilterChange,
    emptyIcon = 'layers-search',
    emptyMessage = 'Aucun résultat',
    navigation
}: CampusListLayoutProps<T>) {
    const AppContextValues = useContext(AppContext) as { themeName: 'light' | 'dark' };
    const themeName = AppContextValues.themeName ?? 'light';
    const theme = style.Theme[themeName];
    const insets = useSafeAreaInsets();

    const [filterVisible, setFilterVisible] = useState(false);
    const route = useRoute();

    // Setup Header Filter Icon if filterOptions exist and navigation is provided
    useEffect(() => {
        if (!navigation || filterOptions.length === 0) return;

        const safeScrollY = globalScrollValues[route.key];
        const scale = safeScrollY?._buttonScale || 1.14;

        navigation.setOptions({
            headerRight: () => (
                <Animated.View style={{ transform: [{ scale }], height: 45, justifyContent: 'center' }}>
                    <TouchableOpacity onPress={() => setFilterVisible(true)} style={{ paddingRight: tokens.space.md }}>
                        <View style={{ 
                            backgroundColor: theme.greyBackground, 
                            width: 45, height: 45, 
                            justifyContent: 'center', 
                            alignItems: 'center', 
                            borderRadius: tokens.radius.md, 
                            flexShrink: 0
                        }}>
                            <MaterialCommunityIcons 
                                name="filter-variant"
                                size={26} 
                                color={selectedFilter !== 'all' && selectedFilter !== undefined ? theme.primary : theme.fontSecondary} 
                            />
                        </View>
                    </TouchableOpacity>
                </Animated.View>
            )
        });
    }, [navigation, theme, route.key, selectedFilter, filterOptions]);

    if (loading) {
        return (
            <SafeAreaView edges={['left', 'right']} style={{ flex: 1, backgroundColor: theme.courseBackground }}>
                <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
                    <ActivityIndicator size="large" color={theme.accent ?? theme.primary} />
                </View>
            </SafeAreaView>
        );
    }

    const isFiltering = searchText.trim().length > 0 || (selectedFilter && selectedFilter !== 'all');

    return (
        <SafeAreaView edges={['left', 'right']} style={{ flex: 1, backgroundColor: theme.courseBackground }}>
            <View style={{ flex: 1 }}>
                <Animated.FlatList
                    data={data}
                    onScroll={onAnimatedScroll as never}
                    scrollEventThrottle={16}
                    keyExtractor={(item: any, index) => item.id ? item.id.toString() : index.toString()}
                    showsVerticalScrollIndicator={false}
                    contentContainerStyle={{ 
                        paddingTop: (insets.top || 0) + 70, 
                        paddingBottom: Math.max(tokens.space.sm, (insets?.bottom || 0)) + (hasSearch ? 80 : 20), 
                        flexGrow: 1 
                    }}
                    renderItem={renderItem}
                    ListEmptyComponent={() => (
                        <View style={{ 
                            alignItems: 'center', 
                            paddingVertical: tokens.space.xl, 
                            paddingHorizontal: tokens.space.lg,
                            marginHorizontal: tokens.space.sm,
                            backgroundColor: theme.cardBackground, 
                            borderRadius: tokens.radius.lg, 
                            borderWidth: 1, 
                            borderColor: theme.border 
                        }}>
                            <MaterialCommunityIcons name={emptyIcon} size={48} color={theme.fontSecondary} style={{ marginBottom: tokens.space.sm }} />
                            <Text style={{ 
                                color: theme.fontSecondary, 
                                fontSize: tokens.fontSize.md,
                                textAlign: 'center'
                            }}>
                                {isFiltering ? Translator.get('NO_RESULTS_FOUND' as Parameters<typeof Translator.get>[0]) : emptyMessage}
                            </Text>
                        </View>
                    )}
                />
            </View>

            {/* SEARCH BAR */}
            {hasSearch && (
                <KeyboardAvoidingView
                    behavior={Platform.OS === 'ios' ? 'position' : undefined}
                    keyboardVerticalOffset={Platform.OS === 'ios' ? 0 : 0}
                    style={{
                        position: 'absolute',
                        bottom: 0,
                        left: 0,
                        right: 0,
                    }}
                >
                    <View style={{
                        paddingBottom: Math.max(tokens.space.sm, (insets?.bottom || 0) - 15)
                    }}>
                        <View style={{
                            flexDirection: 'row',
                            alignItems: 'center',
                            backgroundColor: theme.greyBackground,
                            borderRadius: tokens.radius.md,
                            paddingHorizontal: tokens.space.md,
                            marginHorizontal: tokens.space.md,
                            height: 45,
                            elevation: 5,
                            shadowColor: '#000',
                            shadowOffset: { width: 0, height: 2 },
                            shadowOpacity: 0.2,
                            shadowRadius: 4,
                        }}>
                            <MaterialCommunityIcons
                                name="magnify"
                                size={22}
                                color={theme.fontSecondary}
                                style={{ marginRight: tokens.space.sm }}
                            />
                            <TextInput
                                style={{
                                    flex: 1,
                                    fontSize: tokens.fontSize.md,
                                    color: theme.font,
                                    padding: 0
                                }}
                                placeholder={searchPlaceholder}
                                placeholderTextColor={theme.fontSecondary}
                                onChangeText={onSearchChange}
                                value={searchText}
                                autoCorrect={false}
                            />
                            {searchText.length > 0 && onSearchChange && (
                                <TouchableOpacity
                                    onPress={() => onSearchChange('')}
                                    style={{ padding: tokens.space.xs }}
                                >
                                    <MaterialCommunityIcons name="close-circle" size={18} color={theme.fontSecondary} />
                                </TouchableOpacity>
                            )}
                        </View>
                    </View>
                </KeyboardAvoidingView>
            )}

            {/* FILTER MODAL */}
            {filterOptions.length > 0 && onFilterChange && (
                <Modal animationType="fade" transparent={true} visible={filterVisible} onRequestClose={() => setFilterVisible(false)}>
                    <TouchableWithoutFeedback onPress={() => setFilterVisible(false)}>
                        <View style={(theme.settings?.popup?.background || { flex: 1, backgroundColor: "rgba(0,0,0,0.5)", justifyContent: "center", alignItems: "center" }) as never}>
                            <TouchableWithoutFeedback>
                                <View style={(theme.settings?.popup?.container || { backgroundColor: theme.cardBackground, width: "85%", borderRadius: tokens.radius.xl, padding: tokens.space.lg }) as never}>
                                    <View style={(theme.settings?.popup?.header || { flexDirection: "row", justifyContent: "space-between", alignItems: "center", marginBottom: tokens.space.md }) as never}>
                                        <Text style={theme.settings?.popup?.textHeader || { fontSize: tokens.fontSize.lg, fontWeight: 'bold', color: theme.font }}>
                                            {Translator.get('FILTERS')}
                                        </Text>
                                        <TouchableOpacity onPress={() => setFilterVisible(false)}>
                                            <MaterialIcons name="close" size={28} color={theme.fontSecondary} />
                                        </TouchableOpacity>
                                    </View>

                                    {filterOptions.map((option) => (
                                        <TouchableOpacity 
                                            key={option.id}
                                            onPress={() => { onFilterChange(option.id); setFilterVisible(false); }} 
                                            style={{ 
                                                paddingVertical: tokens.space.md, 
                                                borderBottomWidth: option.id === filterOptions[filterOptions.length - 1].id ? 0 : 1, 
                                                borderColor: theme.border, 
                                                flexDirection: 'row', 
                                                alignItems: 'center' 
                                            }}
                                        >
                                            <MaterialCommunityIcons 
                                                name={selectedFilter === option.id ? "radiobox-marked" : "radiobox-blank"} 
                                                size={22} 
                                                color={selectedFilter === option.id ? theme.primary : theme.fontSecondary} 
                                                style={{ marginRight: tokens.space.sm }} 
                                            />
                                            <Text style={{ 
                                                color: selectedFilter === option.id ? theme.primary : theme.font, 
                                                fontSize: tokens.fontSize.md, 
                                                fontWeight: selectedFilter === option.id ? 'bold' : 'normal' 
                                            }}>
                                                {option.label}
                                            </Text>
                                        </TouchableOpacity>
                                    ))}
                                </View>
                            </TouchableWithoutFeedback>
                        </View>
                    </TouchableWithoutFeedback>
                </Modal>
            )}
        </SafeAreaView>
    );
}

import axios from 'axios';
import qs from 'qs';
import moment from 'moment';
import 'moment/locale/fr';
import { WebApiURL } from '../../../shared/constants/urls';
import { formatDescription } from '../../../shared/utils/formatUtils';

moment.locale('fr');

class CampusApiServiceClass {
    fetchRoomList = async (): Promise<{ id: string; name: string }[] | null> => {
        const options = {
            method: 'GET',
            url: WebApiURL.DOMAIN + WebApiURL.GROUPS,
            params: { searchTerm: '_', pageSize: '10000', resType: '102' },
        };
        try {
            const results = await axios.request(options);
            if (results?.status !== 200) return null;
            if (!results.data) return null;

            return results.data.results
                .filter((e: any) => e.text && e.text.length > 2)
                .map((e: any) => ({ id: e.id, name: e.text }));
        } catch (error) {
            return null;
        }
    };

    extractBuildingsFromRooms = (rooms: { id: string; name: string }[]): Record<string, unknown>[] => {
        const locationsData = require('../../../../assets/locations.json');

        // Find which buildings have freeAccess: true
        const freeAccessBuildings = Object.keys(locationsData).filter(key => locationsData[key].freeAccess === true);

        const buildingsMap = new Map();

        for (const buildingKey of freeAccessBuildings) {
            const loc = locationsData[buildingKey];
            buildingsMap.set(buildingKey, {
                id: 'bat_' + buildingKey.toLowerCase(),
                name: buildingKey,
                rooms: [],
                imageUrl: loc.image,
                lat: loc.lat,
                lng: loc.lng,
                campus: loc.campus || 'Talence',
                schedule: loc.schedule
            });
        }

        for (const room of rooms) {
            if (room.name.toLowerCase().includes('en attente')) continue;

            for (const buildingKey of freeAccessBuildings) {
                // Match the building key strictly
                const regex = new RegExp(`\\b${buildingKey}\\b`, 'i');
                if (regex.test(room.name) || room.name.includes(buildingKey)) {
                    // Nettoyage: retirer le nom du bâtiment et ne garder que "Salle XXX"
                    let cleanName = room.name.replace(/\s*\([^)]*\)$/, '').trim();
                    let finalName = cleanName;
                    const salleIndex = cleanName.toLowerCase().indexOf('salle');
                    if (salleIndex !== -1) {
                        finalName = cleanName.substring(salleIndex).trim();
                    }

                    if (finalName.toLowerCase() === 'salle' || finalName.trim() === '') {
                        break;
                    }

                    buildingsMap.get(buildingKey).rooms.push({
                        id: room.id,
                        name: finalName,
                        fullName: room.name
                    });
                    break;
                }
            }
        }

        return Array.from(buildingsMap.values()).filter((b: any) => b.rooms.length > 0).sort((a: any, b: any) => a.name.localeCompare(b.name));
    };

    fetchRoomsScheduleDay = async (roomIds: string[], date: string): Promise<Record<string, unknown>[] | null> => {
        const endQueryDate = moment(date, 'YYYY-MM-DD').add(1, 'day').format('YYYY-MM-DD');
        const data = {
            start: date,
            end: endQueryDate,
            resType: '102',
            calView: 'agendaDay',
            'federationIds[]': roomIds,
            colourScheme: '3',
        };
        const options = {
            method: 'POST',
            url: WebApiURL.DOMAIN + WebApiURL.CALENDARDATA,
            headers: {
                Connection: 'keep-alive',
                Pragma: 'no-cache',
                'Cache-Control': 'no-cache',
                Accept: 'application/json',
                'Content-Type': 'application/x-www-form-urlencoded; charset=UTF-8',
            },
            data: qs.stringify(data, { arrayFormat: 'repeat' }),
        };

        try {
            const response = await axios.request(options);
            if (response?.status !== 200) return null;

            const eventList = [];
            for (const event of response.data) {
                if (moment(event.start).format('YYYY-MM-DD') !== date) continue;

                const startDate = moment(event.start);
                const endDate = moment(event.end);

                eventList.push({
                    id: event.id,
                    starttime: startDate.format('HH:mm'),
                    endtime: endDate.format('HH:mm'),
                    date: { start: startDate.toISOString(), end: endDate.toISOString() },
                    description: formatDescription(event.description),
                    isVacances: event.eventCategory === 'Vacances' || (event.description && event.description.toLowerCase().includes('vacances'))
                });
            }
            return eventList;
        } catch (error) {
            return null;
        }
    };
}

