export interface HomeScreenProps {
    navigation: import('@react-navigation/native').NavigationProp<Record<string, unknown>>;
}

export interface HomeScreenState {
    completeList: any[] | null;
    sections: any[] | null;
    list: any[] | null;
    emptySearchResults: boolean;
    refreshing: boolean;
    cacheDate: moment.MomentInput | null;
    searchText: string;
}

class HomeScreen extends React.Component<HomeScreenProps, HomeScreenState> {
    static contextType = AppContext;
    // @ts-ignore
    context!: React.ContextType<typeof AppContext>;
    scrollY: Animated.Value;

    constructor(props: HomeScreenProps) {
        super(props);
        this.scrollY = new Animated.Value(0);
        this.state = {
            completeList: null,
            sections: null,
            list: null,
            emptySearchResults: false,
            refreshing: false,
            cacheDate: null,
            searchText: '',
        };
    }

    async componentDidMount() {
        this.props.navigation.setOptions(
            NavBarHelper({
                title: Translator.get('GROUPS'),
                themeName: this.context.themeName,
                scrollY: this.scrollY,
                headerRight: () => (
                    <View style={{ paddingRight: tokens.space.md }}>
                        <SaveGroupButton
                            groupName={[]}
                            themeName={this.context.themeName}
                        />
                    </View>
                ),
            } as never)
        );
        await this.getList();
    }

    generateSections(list, save = false) {
        let sections = [];
        let sectionContent = null;
        let previousSection = null;
        let sectionIndex = -1;

        list.forEach((e) => {
            let splitName = e.name.substring(0, 3);
            e.cleanName = e.name;

            if (splitName !== previousSection) {
                if (previousSection !== null) {
                    sections.push(sectionContent);
                }
                previousSection = splitName;
                sectionContent = {
                    key: previousSection,
                    data: [],
                    sectionIndex: ++sectionIndex,
                    colorIndex: sectionIndex % style.Theme[this.context.themeName].sections.length,
                };
            }

            e.colorIndex = sectionContent.colorIndex;
            e.sectionStyle = style.list.sections[sectionIndex % style.list.sections.length];
            sectionContent.data.push(e);
        });

        sections.push(sectionContent);

        if (save) {
            this.setState({ list, sections, completeList: list, refreshing: false });
        } else {
            this.setState({ list, sections });
        }
    }

    refreshList = async () => {
        this.setState({ refreshing: true });
        await this.fetchList();
    };

    getList = async () => {
        await this.fetchList();
    };

    getCache = async () => {
        let cacheStr = await AsyncStorage.getItem('groups');
        if (cacheStr !== null) {
            const cache = JSON.parse(cacheStr) as { date: string; list: any[] };
            this.setState({ cacheDate: cache.date });
            return cache.list;
        }
        return null;
    };

    fetchList = async () => {
        let list = null;

        if (await isConnected()) {
            try {
                const groupList = await FetchManager.fetchGroupList();
                if (groupList === null) throw 'network error';

                this.setState({ cacheDate: null });
                list = groupList.map((e) => ({ name: e }));
                AsyncStorage.setItem('groups', JSON.stringify({ list, date: moment() })).catch((e) =>
                    console.warn('Échec de la mise en cache des groupes :', e)
                );
            } catch (error) {
                if (error.response) {
                    Toast.show(Translator.get('ERROR_WITH_CODE'), {
                        duration: Toast.durations.LONG,
                        position: Toast.positions.BOTTOM,
                    });
                } else if (error.request) {
                    Toast.show(Translator.get('NO_CONNECTION'), {
                        duration: Toast.durations.SHORT,
                        position: Toast.positions.BOTTOM,
                    });
                } else {
                    Toast.show(Translator.get('ERROR_WITH_MESSAGE', error.message), {
                        duration: Toast.durations.LONG,
                        position: Toast.positions.BOTTOM,
                    });
                }
                list = await this.getCache();
            }
        } else {
            Toast.show(Translator.get('NO_CONNECTION'), {
                duration: Toast.durations.SHORT,
                position: Toast.positions.BOTTOM,
            });
            list = await this.getCache();
        }

        if (list !== null) {
            this.generateSections(list, true);
        }
    };

    openGroup = (name) => {
        const { navigate } = this.props.navigation;
        navigate('Group', { name });
    };

    search(input) {
        this.setState({ sections: null, emptySearchResults: false });
        let list = this.state.completeList;
        if (input.length !== 0) {
            let regex = new RegExp(input, 'gi');
            list = list.filter((e) => {
                return e.name.replace(/_/g, ' ').match(regex);
            });
        }
        if (list.length > 0) {
            this.setState({ emptySearchResults: false });
            this.generateSections(list, false);
        } else {
            this.setState({ emptySearchResults: true });
        }
    }

    render() {
        const theme = style.Theme[this.context.themeName];
        let content = null;

        const searchInput = (
            <View style={{
                flexDirection: 'row',
                alignItems: 'center',
                backgroundColor: theme.greyBackground,
                borderRadius: tokens.radius.md,
                paddingHorizontal: tokens.space.md,
                marginHorizontal: tokens.space.md,
                marginTop: tokens.space.xs,
                marginBottom: tokens.space.md,
                height: 40,
            }}>
                <MaterialCommunityIcons
                    name="magnify"
                    size={22}
                    color={theme.fontSecondary}
                    style={{ marginRight: tokens.space.sm }}
                />
                <TextInput
                    style={{
                        flex: 1,
                        fontSize: tokens.fontSize.md,
                        color: theme.font,
                    }}
                    placeholder={Translator.get('SEARCH')}
                    placeholderTextColor={theme.fontSecondary}
                    onChangeText={(text) => {
                        this.setState({ searchText: text });
                        this.search(text);
                    }}
                    value={this.state.searchText}
                    autoCorrect={false}
                />
                {this.state.searchText.length > 0 && (
                    <TouchableOpacity
                        onPress={() => {
                            this.setState({ searchText: '' });
                            this.search('');
                        }}
                        style={{ padding: tokens.space.xs }}
                    >
                        <MaterialCommunityIcons name="close-circle" size={18} color={theme.fontSecondary} />
                    </TouchableOpacity>
                )}
            </View>
        );

        const cache = this.state.cacheDate ? (
            <View style={{
                flexDirection: 'row',
                alignItems: 'center',
                backgroundColor: theme.greyBackground,
                paddingHorizontal: tokens.space.md,
                paddingVertical: tokens.space.sm,
                borderBottomWidth: 1,
                borderBottomColor: theme.border,
            }}>
                <MaterialCommunityIcons
                    name="clock-outline"
                    size={14}
                    color={theme.fontSecondary}
                    style={{ marginRight: tokens.space.xs }}
                />
                <Text style={{ fontSize: tokens.fontSize.xs, color: theme.fontSecondary }}>
                    {Translator.get('OFFLINE_DISPLAY_FROM_DATE', moment(this.state.cacheDate).format('DD/MM/YYYY HH:mm'))}
                </Text>
            </View>
        ) : null;

        if (this.state.emptySearchResults) {
            content = (
                <View style={[(style.schedule.course.noCourse as never), { backgroundColor: theme.greyBackground }]}>
                    <MaterialCommunityIcons name="magnify-close" size={48} color={theme.fontSecondary} style={{ marginBottom: tokens.space.md, opacity: 0.4 }} />
                    <Text style={[style.schedule.course.noCourseText, { color: theme.font }]}>
                        {Translator.get('NO_GROUP_FOUND_WITH_THIS_SEARCH')}
                    </Text>
                </View>
            );
        } else if (this.state.sections === null) {
            content = (
                <View style={{ flex: 1, justifyContent: 'center', backgroundColor: theme.background }}>
                    <ActivityIndicator size="large" color={theme.primary} animating={true} />
                </View>
            );
        } else {
            content = (
                <Animated.SectionList
                    onScroll={Animated.event(
                        [{ nativeEvent: { contentOffset: { y: this.scrollY } } }],
                        { useNativeDriver: false }
                    )}
                    scrollEventThrottle={16}
                    contentContainerStyle={{ paddingTop: 0, paddingBottom: tokens.space.xxl }}
                    scrollIndicatorInsets={{ top: 0 }}
                    renderItem={({ item, index }) => (
                        <GroupRow name={item.name} cleanName={item.cleanName} sectionStyle={item.sectionStyle} key={index} color={theme.sections[item.colorIndex]} fontColor={theme.font} openGroup={this.openGroup} />
                    )}
                    renderSectionHeader={({ section }) => (
                        <SectionListHeader title={section.key} key={section.key} sectionIndex={section.sectionIndex} color={theme.sections[section.colorIndex]} headerColor={theme.sectionsHeaders[section.colorIndex]} />
                    )}
                    sections={this.state.sections}
                    keyExtractor={(item, index) => index.toString()}
                    initialNumToRender={20}
                    onEndReachedThreshold={0.1}
                    style={[style.list.sectionList, { backgroundColor: theme.greyBackground }]}
                    onRefresh={this.refreshList}
                    refreshing={this.state.refreshing}
                    stickySectionHeadersEnabled={true}
                    showsVerticalScrollIndicator={false}
                />
            );
        }

        return (
            <SafeAreaInsetsContext.Consumer>
                {(insets) => (
                    <View style={[style.list.homeView, { backgroundColor: theme.background }]}>
                        <View style={{ 
                            paddingTop: (insets?.top || 0) + 65,
                            backgroundColor: theme.cardBackground,
                            borderBottomWidth: 1,
                            borderBottomColor: theme.border,
                            ...tokens.shadow.sm,
                        }}>
                            {searchInput}
                            {cache}
                        </View>
                        {content}
                    </View>
                )}
            </SafeAreaInsetsContext.Consumer>
        );
    }
}

export default HomeScreen;

import axios from 'axios';
import qs from 'qs';
import moment from 'moment';
import 'moment/locale/fr';
import { WebApiURL } from '../../../shared/constants/urls';
import { formatDescription, upperCaseFirstLetter } from '../../../shared/utils/formatUtils';

moment.locale('fr');

class PlanningApiServiceClass {
    fetchGroupList = async (): Promise<string[] | null> => {
        const options = {
            method: 'GET',
            url: WebApiURL.DOMAIN + WebApiURL.GROUPS,
            params: { searchTerm: '_', pageSize: '10000', resType: '103' },
        };
        try {
            const results = await axios.request(options);
            if (results?.status !== 200) return null;
            if (!results.data) return null;

            return results.data.results
                .map((e: any) => e.id)
                .filter((e: string) => e.length > 2)
                .sort();
        } catch (error) {
            return null;
        }
    };

    sortFunctionGroup = (a: { subject: string; starttime: string }, b: { subject: string; starttime: string }): number => {
        const regexUE = RegExp('([0-9][A-Z0-9]+) (.+)', 'im');
        let subectA = a.subject.toUpperCase();
        let subectB = b.subject.toUpperCase();
        const matchA = regexUE.exec(subectA);
        const matchB = regexUE.exec(subectB);

        if (matchA && matchA.length === 3) subectA = `${matchA[2]}`;
        if (matchB && matchB.length === 3) subectB = `${matchB[2]}`;

        if (a.starttime > b.starttime) return 1;
        if (a.starttime < b.starttime) return -1;
        else if (subectA > subectB) return 1;
        else if (subectA < subectB) return -1;
        return 0;
    };

    fetchCalendarDay = async (group: string, date: string): Promise<Record<string, unknown>[] | null> => {
        const endQueryDate = moment(date, 'YYYY-MM-DD').add(1, 'day').format('YYYY-MM-DD');
        const data = {
            start: date,
            end: endQueryDate,
            resType: '103',
            calView: 'agendaDay',
            'federationIds[]': group,
            colourScheme: '3',
        };
        const options = {
            method: 'POST',
            url: WebApiURL.DOMAIN + WebApiURL.CALENDARDATA,
            headers: {
                Connection: 'keep-alive',
                Pragma: 'no-cache',
                'Cache-Control': 'no-cache',
                Accept: 'application/json',
                'Content-Type': 'application/x-www-form-urlencoded; charset=UTF-8',
            },
            data: qs.stringify(data, { arrayFormat: 'repeat' }),
        };

        try {
            const response = await axios.request(options);
            if (response?.status !== 200) return null;

            const eventList = [];
            for (const event of response.data) {
                if (event.eventCategory === 'Vacances') continue;
                if (moment(event.start).format('YYYY-MM-DD') !== date) continue;

                const startDate = moment(event.start);
                const endDate = moment(event.end);
                const starttime = startDate.format('HH:mm');
                const endtime = endDate.format('HH:mm');

                let subject = event.eventCategory;
                if (event.modules !== null) subject = event.modules.shift();

                const unfilteredDescription = formatDescription(event.description).split(';');
                const description = [];
                for (const field of unfilteredDescription) {
                    if (!field.includes(event.eventCategory) && !field.includes(subject)) {
                        description.push(field.trim());
                    }
                }

                let toFilter = null;
                if (description[0]?.includes(group)) {
                    let filter = description[0].replace(group, '').replace('-', '').trim();
                    toFilter = filter !== '' ? filter : null;
                }

                eventList.push({
                    id: event.id,
                    style: 'style="background-color:' + event.backgroundColor + '"',
                    color: event.backgroundColor,
                    schedule: starttime + '-' + endtime + ' ' + event.eventCategory,
                    starttime,
                    endtime,
                    date: { start: startDate.toISOString(), end: endDate.toISOString() },
                    subject,
                    description: description.filter((e) => e != '').join('\n'),
                    category: event.eventCategory,
                    group,
                    toFilter,
                });
            }
            return eventList.sort(this.sortFunctionGroup);
        } catch (error) {
            return null;
        }
    };

    fetchCalendarWeek = async (group: string, week: { year: number; week: number }): Promise<Record<string, unknown>[] | null> => {
        const searchDate = moment().year(week.year).isoWeek(week.week);
        const begin = searchDate.startOf('week').format('YYYY-MM-DD');
        const end = searchDate.endOf('week').format('YYYY-MM-DD');
        const data = {
            start: begin,
            end: end,
            resType: '103',
            calView: 'agendaWeek',
            'federationIds[]': group,
            colourScheme: '3',
        };
        const options = {
            method: 'POST',
            url: WebApiURL.DOMAIN + WebApiURL.CALENDARDATA,
            headers: {
                Connection: 'keep-alive',
                Pragma: 'no-cache',
                'Cache-Control': 'no-cache',
                Accept: 'application/json',
                'Content-Type': 'application/x-www-form-urlencoded; charset=UTF-8',
            },
            data: qs.stringify(data, { arrayFormat: 'repeat' }),
        };

        try {
            const response = await axios.request(options);
            if (response?.status !== 200) return null;

            const eventList = Array.from({ length: 6 }).map((_, i) => ({
                dayNumber: String(i + 1),
                dayTimestamp: searchDate.clone().startOf('week').add(i, 'day').unix(),
                courses: [] as Record<string, unknown>[],
            }));

            for (const event of response.data) {
                if (event.eventCategory === 'Vacances') continue;

                const startDate = moment(event.start);
                const endDate = moment(event.end);
                const day = upperCaseFirstLetter(moment(startDate).format('dddd L'));
                const dayNumberInt = moment(startDate).isoWeekday();

                if (dayNumberInt < 1 || dayNumberInt > 6) continue;

                const dayNumber = String(dayNumberInt);
                const starttime = startDate.format('HH:mm');
                const endtime = endDate.format('HH:mm');

                let subject = event.eventCategory;
                if (event.modules !== null) subject = event.modules.shift();

                const unfilteredDescription = formatDescription(event.description).split('\n');
                const description = [];
                for (const field of unfilteredDescription) {
                    if (!field.includes(event.eventCategory) && !field.includes(subject)) {
                        description.push(field.trim());
                    }
                }

                let toFilter = null;
                if (description[0]?.includes(group)) {
                    let filter = description[0].replace(group, '').replace('-', '').trim();
                    toFilter = filter !== '' ? filter : null;
                }

                eventList[dayNumberInt - 1].courses.push({
                    id: event.id,
                    style: 'style="background-color:' + event.backgroundColor + '"',
                    color: event.backgroundColor,
                    schedule: starttime + '-' + endtime + ' ' + event.eventCategory,
                    starttime,
                    endtime,
                    date: { start: startDate.toISOString(), end: endDate.toISOString() },
                    subject,
                    description: description.filter((e) => e != '').join('\n'),
                    category: event.eventCategory,
                    group,
                    day,
                    dayNumber,
                    toFilter,
                });
            }

            for (const day of eventList) {
                day.courses.sort(this.sortFunctionGroup);
            }

            return eventList;
        } catch (error) {
            return null;
        }
    };

    fetchCalendarForSynchronization = async (group: string): Promise<Record<string, unknown>[] | null | void> => {
        const currentDate = moment();
        const begin = moment().set('month', 7).startOf('month');
        const end = moment().set('month', 7).startOf('month').add(1, 'year');

        if (currentDate.isBefore(begin)) {
            begin.subtract(1, 'year');
            end.subtract(1, 'year');
        }

        const data = {
            start: begin.format('YYYY-MM-DD'),
            end: end.format('YYYY-MM-DD'),
            resType: '103',
            calView: 'agendaWeek',
            'federationIds[]': group,
            colourScheme: '3',
        };

        const options = {
            method: 'POST',
            url: WebApiURL.DOMAIN + WebApiURL.CALENDARDATA,
            headers: {
                Connection: 'keep-alive',
                Pragma: 'no-cache',
                'Cache-Control': 'no-cache',
                Accept: 'application/json',
                'Content-Type': 'application/x-www-form-urlencoded; charset=UTF-8',
            },
            data: qs.stringify(data),
        };

        try {
            const response = await axios.request(options);
            if (response?.status !== 200) return;

            const events = [];
            for (const event of response.data) {
                if (event.eventCategory === 'Vacances') continue;

                const startDate = moment(event.start);
                const endDate = moment(event.end);
                const day = upperCaseFirstLetter(moment(startDate).format('dddd L'));
                const dayNumberInt = moment(startDate).isoWeekday();
                const dayNumber = String(dayNumberInt);

                const starttime = startDate.format('HH:mm');
                const endtime = endDate.format('HH:mm');

                let subject = event.eventCategory;
                if (event.modules !== null) subject = event.modules.shift();

                const unfilteredDescription = formatDescription(event.description).split(';');
                const description = [];

                for (const field of unfilteredDescription) {
                    if (!field.includes(event.eventCategory) && !field.includes(subject)) {
                        description.push(field.trim());
                    }
                }

                events.push({
                    id: event.id,
                    style: 'style="background-color:' + event.backgroundColor + '"',
                    color: event.backgroundColor,
                    schedule: starttime + '-' + endtime + ' ' + event.eventCategory,
                    starttime,
                    endtime,
                    date: { start: startDate.toISOString(), end: endDate.toISOString() },
                    subject,
                    description: description.filter((e) => e != '').join('\n'),
                    category: event.eventCategory,
                    group,
                    day,
                    dayNumber,
                });
            }

            return events.sort(this.sortFunctionGroup);
        } catch (error) {
            return null;
        }
    };
}

