// ── CONTEXTE & DEVICE ─────────────────────────────────
export const AppContext = React.createContext<{ themeName?: string; favoriteGroups?: string[]; filters?: string[] }>({});
export const AppContextProvider = AppContext.Provider;

export function deviceLanguage(): string {
    if (Platform.OS === 'ios') {
        const settings = NativeModules.SettingsManager?.settings;
        return settings?.AppleLocale || settings?.AppleLanguages[0] || 'en_US';
    } 
    return NativeModules.I18nManager?.localeIdentifier || 'en_US';
}

export function languageFromDevice(): string {
    const lang = deviceLanguage();
    if (lang.startsWith('fr')) return 'fr';
    if (lang.startsWith('es')) return 'es';
    return 'en';
}

export async function isConnected(): Promise<boolean | null> {
    const netInfo = await NetInfo.fetch();
    return netInfo.isConnected;
}

// ── UTILITAIRES DIVERS ───────────────────────────────────
export function treatTitle(str: string | string[]): string {
    if (Array.isArray(str)) {
        return 'Mon Planning';
    }
    str = str.replace(/_/g, ' ');
    if (str.length > 18) {
        return str.charAt(18) === ' ' ? `${str.substr(0, 18)}…` : `${str.substr(0, 18)} …`;
    }
    return str;
}

export function upperCaseFirstLetter(string: string): string {
    return string.charAt(0).toUpperCase() + string.slice(1);
}

export function isArraysEquals(a: unknown[], b: unknown[]): boolean {
    if (a.length !== b.length) return false;
    for (let i = 0; i < a.length; i++) {
        if (a[i] !== b[i]) return false;
    }
    return true;
}

function getLocation(house: string): Record<string, unknown> | null {
    return locations[house] ? { title: house, ...locations[house] } : null;
}

export function getLocations(str: string): Record<string, unknown>[] {
    let lines = str.split(' | ');
    let locs = [];
    lines.forEach((line) => {
        let house = line.split('/')[0].replace(' ', '');
        let loc = getLocation(house);
        if (loc) locs.push(loc);
    });
    return locs;
}

export function getLocationsInText(str: string): Record<string, unknown>[] {
    let regexBuilding = RegExp('([A-Z][0-9]+)', 'im');
    let match = regexBuilding.exec(str);
    if (match && match.length === 2) {
        let loc = getLocation(match[1]);
        if (loc) return [loc];
    }
    return [];
}

// ── GESTION DES COURS ───────────────────────────────
export const CourseManager = {
    computeCourseUE: (course: Record<string, unknown>): Record<string, unknown> => {
        let regexUE = RegExp('([0-9][A-Z0-9]+) (.+)', 'im');
        if (course.subject && course.subject !== 'N/C') {
            let match = regexUE.exec(course.subject as string);
            if (match && match.length === 3) {
                course.UE = match[1];
                course.subject = `${match[2]}`;
            } else {
                course.UE = null;
            }
        }
        return course;
    },
    filterCourse: (isFavorite: boolean, course: Record<string, unknown>, filtersList: unknown): boolean => {
        if (!isFavorite) return true;
        if (course.UE !== null && filtersList instanceof Array && filtersList.includes(course.UE)) {
            return false;
        }
        return true;
    }
};

