// ── Bouton des Paramètres ──────────────────────────────────────
export interface SettingsButtonProps {
    theme?: any;
    onPress?: () => void;
    leftIcon?: keyof typeof MaterialIcons.glyphMap | keyof typeof MaterialCommunityIcons.glyphMap;
    leftIconAnimation?: string;
    leftText?: string;
    rightText?: string;
    disabled?: boolean;
    switchValue?: boolean;
    onSwitchToggle?: (value: boolean) => void;
}
export const SettingsButton = ({ theme, onPress, leftIcon, leftIconAnimation, leftText, rightText, disabled, switchValue, onSwitchToggle }: SettingsButtonProps) => {
    const rotatingAnimation = useRef(new Animated.Value(0)).current;

    useEffect(() => {
        if (leftIconAnimation === 'rotate') {
            Animated.loop(
                Animated.timing(rotatingAnimation, {
                    duration: 1000,
                    toValue: 360,
                    useNativeDriver: true,
                }),
            ).start();
        } else {
            rotatingAnimation.stopAnimation();
            rotatingAnimation.setValue(0);
        }
    }, [leftIconAnimation]);

    const rotate = rotatingAnimation.interpolate({
        inputRange: [0, 1],
        outputRange: ['0deg', '360deg'],
    });

    if (!theme?.button) return null;

    const isMaterialIcon = ['settings', 'language', 'filter-list', 'sync-disabled'].includes(leftIcon);
    const IconComponent = isMaterialIcon ? MaterialIcons : MaterialCommunityIcons;

    return (
        <TouchableOpacity
            onPress={onPress}
            disabled={disabled}
            style={[(theme as any).button, { flexDirection: 'row', alignItems: 'center' }, disabled && { opacity: 0.5}]}>
            {leftIcon && (
                <Animated.View style={{ transform: leftIconAnimation ? [{ rotate }] : [] }}>
                    <IconComponent name={leftIcon as never} size={24} style={(theme as any).leftIcon} />
                </Animated.View>
            )}
            <Text style={[(theme as any).buttonMainText, { flex: 1 }]}>{leftText}</Text>
            {onSwitchToggle !== undefined ? (
                <Switch
                    style={{ marginLeft: 'auto', marginRight: (theme as any).leftIcon?.marginLeft }}
                    trackColor={(theme as any).switchTrack}
                    thumbColor={'#FFFFFF'}
                    value={switchValue}
                    onValueChange={onSwitchToggle}
                />
            ) : (
                <Text style={(theme as any).buttonSecondaryText}>{rightText}</Text>
            )}
            {!onSwitchToggle && (
                <MaterialCommunityIcons name="chevron-right" size={22} style={(theme as any).rightIcon} />
            )}
        </TouchableOpacity>
    );
};

